{
  "name": "PortfolioGenie AI",
  "description": "A high-end AI-powered resume and personal website builder that constructs your professional identity through a natural conversational interview.",
  "requestFramePermissions": []
}

export interface Experience {
  company: string;
  role: string;
  duration: string;
  description: string[];
}

export interface Education {
  institution: string;
  degree: string;
  year: string;
}

export interface Project {
  title: string;
  description: string;
  techStack: string[];
  link?: string;
}

export interface UserProfile {
  name: string;
  title: string;
  email: string;
  phone: string;
  location: string;
  summary: string;
  skills: string[];
  experience: Experience[];
  education: Education[];
  projects: Project[];
  socialLinks: {
    linkedin?: string;
    github?: string;
    portfolio?: string;
  };
  themeColor: string;
}

export type MessageRole = 'user' | 'assistant' | 'system';

export interface Message {
  role: MessageRole;
  content: string;
}

export type AppState = 'landing' | 'chatting' | 'preview';

import { GoogleGenAI, Type } from "@google/genai";
import { Message, UserProfile } from "../types";
import { SYSTEM_PROMPT } from "../constants";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const chatWithGenie = async (history: Message[]) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: history.map(m => ({
        role: m.role === 'assistant' ? 'model' : 'user',
        parts: [{ text: m.content }]
      })),
      config: {
        systemInstruction: SYSTEM_PROMPT,
        temperature: 0.7,
      }
    });
    return response.text || "I'm having trouble thinking right now. Could you repeat that?";
  } catch (error) {
    console.error("Gemini Chat Error:", error);
    return "Something went wrong with our connection to the Genie. Please try again.";
  }
};

export const extractProfileData = async (history: Message[]): Promise<UserProfile | null> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        {
          role: 'user',
          parts: [{ text: `Based on the following conversation history, extract the user's professional profile information into the specified JSON format. If information is missing, use empty strings or empty arrays.

          Conversation:
          ${history.map(m => `${m.role}: ${m.content}`).join('\n')}
          ` }]
        }
      ],
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            name: { type: Type.STRING },
            title: { type: Type.STRING },
            email: { type: Type.STRING },
            phone: { type: Type.STRING },
            location: { type: Type.STRING },
            summary: { type: Type.STRING },
            skills: { type: Type.ARRAY, items: { type: Type.STRING } },
            experience: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  company: { type: Type.STRING },
                  role: { type: Type.STRING },
                  duration: { type: Type.STRING },
                  description: { type: Type.ARRAY, items: { type: Type.STRING } }
                }
              }
            },
            education: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  institution: { type: Type.STRING },
                  degree: { type: Type.STRING },
                  year: { type: Type.STRING }
                }
              }
            },
            projects: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  title: { type: Type.STRING },
                  description: { type: Type.STRING },
                  techStack: { type: Type.ARRAY, items: { type: Type.STRING } },
                  link: { type: Type.STRING }
                }
              }
            },
            socialLinks: {
              type: Type.OBJECT,
              properties: {
                linkedin: { type: Type.STRING },
                github: { type: Type.STRING },
                portfolio: { type: Type.STRING }
              }
            },
            themeColor: { type: Type.STRING }
          }
        }
      }
    });

    const data = JSON.parse(response.text);
    return data as UserProfile;
  } catch (error) {
    console.error("Extraction Error:", error);
    return null;
  }
};

