import React, { useState, useEffect, useRef, useCallback } from 'react';
import { AppState, Message, UserProfile } from './types';
import { INITIAL_PROFILE, THEME_COLORS } from './constants';
import { chatWithGenie, extractProfileData } from './services/geminiService';
import ResumePreview from './components/ResumePreview';
import WebsitePreview from './components/WebsitePreview';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>('landing');
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputText, setInputText] = useState('');
  const [profile, setProfile] = useState<UserProfile>(INITIAL_PROFILE);
  const [isTyping, setIsTyping] = useState(false);
  const [previewTab, setPreviewTab] = useState<'resume' | 'website'>('resume');
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isTyping]);

  const startInterview = async () => {
    setAppState('chatting');
    setIsTyping(true);
    const initialGreeting: Message = { 
      role: 'assistant', 
      content: "Hello! I'm PortfolioGenie. I'm here to help you build a stunning resume and a personal website. Let's start with the basics—what is your full name and what role are you targeting (e.g., Software Engineer, Marketing Manager)?" 
    };
    setMessages([initialGreeting]);
    setIsTyping(false);
  };

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputText.trim() || isTyping) return;

    const userMsg: Message = { role: 'user', content: inputText };
    setMessages(prev => [...prev, userMsg]);
    setInputText('');
    setIsTyping(true);

    try {
      const response = await chatWithGenie([...messages, userMsg]);
      setMessages(prev => [...prev, { role: 'assistant', content: response }]);
    } catch (err) {
      console.error(err);
    } finally {
      setIsTyping(false);
    }
  };

  const generatePreview = async () => {
    setIsTyping(true);
    const data = await extractProfileData(messages);
    if (data) {
      setProfile(prev => ({ ...data, themeColor: prev.themeColor }));
      setAppState('preview');
    }
    setIsTyping(false);
  };

  const downloadPDF = () => {
    window.print();
  };

  if (appState === 'landing') {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-900 text-white p-6 overflow-hidden relative">
        <div className="absolute top-0 left-0 w-full h-full bg-[radial-gradient(circle_at_top_right,rgba(79,70,229,0.15),transparent)] pointer-events-none"></div>
        <div className="max-w-4xl text-center z-10">
          <div className="mb-6 inline-block px-4 py-1.5 bg-indigo-500/10 border border-indigo-500/20 rounded-full text-indigo-400 text-sm font-bold tracking-widest uppercase">
            Powered by Gemini AI
          </div>
          <h1 className="text-6xl md:text-8xl font-serif font-bold mb-8 leading-tight tracking-tighter">
            Elevate your <span className="italic bg-clip-text text-transparent bg-gradient-to-r from-indigo-400 to-cyan-300">professional</span> story.
          </h1>
          <p className="text-xl text-slate-400 mb-12 max-w-2xl mx-auto leading-relaxed">
            PortfolioGenie interviews you to craft a high-performance resume and a breathtaking personal website in minutes. No coding, no templates, just your story.
          </p>
          <button 
            onClick={startInterview}
            className="group px-10 py-5 bg-white text-slate-900 text-xl font-bold rounded-full hover:bg-indigo-50 transition-all flex items-center gap-4 mx-auto shadow-2xl shadow-indigo-500/20"
          >
            Start My Journey
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 group-hover:translate-x-1 transition-transform" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14 5l7 7m0 0l-7 7m7-7H3" />
            </svg>
          </button>
        </div>
        <div className="mt-24 grid grid-cols-3 gap-8 text-sm text-slate-500 uppercase tracking-widest font-bold">
          <div className="flex items-center gap-2"><span className="w-2 h-2 rounded-full bg-indigo-500"></span> AI Interview</div>
          <div className="flex items-center gap-2"><span className="w-2 h-2 rounded-full bg-emerald-500"></span> Instant Resume</div>
          <div className="flex items-center gap-2"><span className="w-2 h-2 rounded-full bg-rose-500"></span> Personal Site</div>
        </div>
      </div>
    );
  }

  if (appState === 'chatting') {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col">
        <header className="bg-white border-b px-8 py-4 flex justify-between items-center sticky top-0 z-20">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white font-black text-xl">P</div>
            <div>
              <h2 className="font-bold text-slate-900 leading-none">PortfolioGenie</h2>
              <span className="text-[10px] text-slate-400 uppercase tracking-widest font-black">AI Career Consultant</span>
            </div>
          </div>
          <div className="flex items-center gap-4">
            <button 
              onClick={generatePreview}
              className="px-6 py-2.5 bg-indigo-600 text-white rounded-lg font-bold hover:bg-indigo-700 transition-colors shadow-lg shadow-indigo-600/10"
              disabled={messages.length < 4 || isTyping}
            >
              Generate Magic
            </button>
          </div>
        </header>

        <main className="flex-1 flex flex-col max-w-4xl mx-auto w-full p-4 overflow-y-auto pt-12 pb-32">
          {messages.map((m, i) => (
            <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'} mb-8`}>
              <div className={`max-w-[85%] rounded-3xl p-6 ${m.role === 'user' ? 'bg-indigo-600 text-white rounded-tr-none' : 'bg-white text-slate-800 rounded-tl-none shadow-sm border border-slate-100'}`}>
                <p className="text-lg leading-relaxed">{m.content}</p>
              </div>
            </div>
          ))}
          {isTyping && (
            <div className="flex justify-start mb-8 animate-pulse">
              <div className="bg-white p-4 rounded-3xl rounded-tl-none shadow-sm border border-slate-100 flex gap-2 items-center">
                <div className="w-2 h-2 bg-indigo-400 rounded-full"></div>
                <div className="w-2 h-2 bg-indigo-400 rounded-full"></div>
                <div className="w-2 h-2 bg-indigo-400 rounded-full"></div>
              </div>
            </div>
          )}
          <div ref={messagesEndRef} />
        </main>

        <footer className="bg-white/80 backdrop-blur-md border-t p-6 sticky bottom-0 z-20">
          <form onSubmit={handleSendMessage} className="max-w-4xl mx-auto flex gap-4">
            <input 
              type="text" 
              value={inputText}
              onChange={(e) => setInputText(e.target.value)}
              placeholder="Tell Genie about your experiences..."
              className="flex-1 bg-slate-100 border-none rounded-2xl px-6 py-4 focus:ring-2 focus:ring-indigo-500 outline-none text-lg"
              disabled={isTyping}
            />
            <button 
              type="submit"
              className="w-14 h-14 bg-indigo-600 text-white rounded-2xl flex items-center justify-center hover:bg-indigo-700 transition-colors disabled:opacity-50"
              disabled={!inputText.trim() || isTyping}
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" />
              </svg>
            </button>
          </form>
        </footer>
      </div>
    );
  }

  if (appState === 'preview') {
    return (
      <div className="min-h-screen bg-slate-100 flex flex-col">
        <header className="bg-white border-b px-8 py-4 flex justify-between items-center sticky top-0 z-30 no-print">
          <div className="flex items-center gap-6">
             <button onClick={() => setAppState('chatting')} className="text-slate-400 hover:text-slate-900 transition-colors">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" />
                </svg>
             </button>
             <div className="h-6 w-px bg-slate-200"></div>
             <div className="flex bg-slate-100 p-1 rounded-xl">
                <button 
                  onClick={() => setPreviewTab('resume')}
                  className={`px-4 py-1.5 rounded-lg text-sm font-bold transition-all ${previewTab === 'resume' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500 hover:text-slate-700'}`}
                >
                  Resume
                </button>
                <button 
                  onClick={() => setPreviewTab('website')}
                  className={`px-4 py-1.5 rounded-lg text-sm font-bold transition-all ${previewTab === 'website' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500 hover:text-slate-700'}`}
                >
                  Website
                </button>
             </div>
          </div>

          <div className="flex items-center gap-4">
             {previewTab === 'website' && (
                <div className="flex gap-2 mr-4">
                   {THEME_COLORS.map(c => (
                     <button 
                       key={c.name}
                       onClick={() => setProfile(p => ({ ...p, themeColor: c.value }))}
                       className={`w-6 h-6 rounded-full border-2 ${profile.themeColor === c.value ? 'border-slate-900' : 'border-transparent'}`}
                       style={{ backgroundColor: c.value }}
                       title={c.name}
                     />
                   ))}
                </div>
             )}
             <button 
              onClick={downloadPDF}
              className="flex items-center gap-2 px-6 py-2 bg-slate-900 text-white rounded-lg font-bold hover:bg-slate-800 transition-colors"
             >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                </svg>
                {previewTab === 'resume' ? 'Download PDF' : 'Print Preview'}
             </button>
          </div>
        </header>

        <main className="flex-1 overflow-y-auto p-8 flex justify-center">
          {previewTab === 'resume' ? (
            <ResumePreview profile={profile} />
          ) : (
            <div className="w-full max-w-[1200px] shadow-2xl rounded-2xl overflow-hidden border border-slate-200 bg-white">
              <WebsitePreview profile={profile} />
            </div>
          )}
        </main>
      </div>
    );
  }

  return null;
};

export default App;

