export type MessageRole = 'user' | 'assistant' | 'system';

export interface Attachment {
  mimeType: string;
  data: string; // base64
  name: string;
}

export interface GroundingSource {
  title: string;
  uri: string;
}

export interface Message {
  role: MessageRole;
  content: string;
  attachments?: Attachment[];
  sources?: GroundingSource[];
}

export type AppState = 'landing' | 'chatting' | 'preview';

import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { Message, UserProfile, Attachment, GroundingSource } from "../types";
import { SYSTEM_PROMPT } from "../constants";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const chatWithGenie = async (
  history: Message[], 
  options: { thinkingMode?: boolean; attachments?: Attachment[] } = {}
) => {
  try {
    const { thinkingMode, attachments } = options;

    // Choose model based on requirements
    // Complex reasoning/Image/Video -> Pro
    // General chat with search -> Flash
    const modelName = (thinkingMode || (attachments && attachments.length > 0)) 
      ? 'gemini-3-pro-preview' 
      : 'gemini-3-flash-preview';

    const config: any = {
      systemInstruction: SYSTEM_PROMPT,
      temperature: 0.7,
    };

    if (thinkingMode) {
      config.thinkingConfig = { thinkingBudget: 32768 };
    }

    if (!thinkingMode && !attachments?.length) {
      config.tools = [{ googleSearch: {} }];
    }

    const contents = history.map(m => {
      const parts: any[] = [{ text: m.content }];

      if (m.attachments) {
        m.attachments.forEach(att => {
          parts.push({
            inlineData: {
              mimeType: att.mimeType,
              data: att.data
            }
          });
        });
      }

      return {
        role: m.role === 'assistant' ? 'model' : 'user',
        parts
      };
    });

    const response: GenerateContentResponse = await ai.models.generateContent({
      model: modelName,
      contents,
      config
    });

    const text = response.text || "I'm having trouble thinking right now.";

    // Extract grounding sources if they exist
    const sources: GroundingSource[] = [];
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    if (chunks) {
      chunks.forEach((chunk: any) => {
        if (chunk.web) {
          sources.push({
            title: chunk.web.title || chunk.web.uri,
            uri: chunk.web.uri
          });
        }
      });
    }

    return { text, sources };
  } catch (error) {
    console.error("Gemini Chat Error:", error);
    return { text: "Something went wrong with our connection to the Genie. Please try again.", sources: [] };
  }
};

export const extractProfileData = async (history: Message[]): Promise<UserProfile | null> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        {
          role: 'user',
          parts: [{ text: `Based on the following conversation history, extract the user's professional profile information into the specified JSON format. If information is missing, use empty strings or empty arrays.

          Conversation:
          ${history.map(m => `${m.role}: ${m.content}`).join('\n')}
          ` }]
        }
      ],
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            name: { type: Type.STRING },
            title: { type: Type.STRING },
            email: { type: Type.STRING },
            phone: { type: Type.STRING },
            location: { type: Type.STRING },
            summary: { type: Type.STRING },
            skills: { type: Type.ARRAY, items: { type: Type.STRING } },
            experience: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  company: { type: Type.STRING },
                  role: { type: Type.STRING },
                  duration: { type: Type.STRING },
                  description: { type: Type.ARRAY, items: { type: Type.STRING } }
                }
              }
            },
            education: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  institution: { type: Type.STRING },
                  degree: { type: Type.STRING },
                  year: { type: Type.STRING }
                }
              }
            },
            projects: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  title: { type: Type.STRING },
                  description: { type: Type.STRING },
                  techStack: { type: Type.ARRAY, items: { type: Type.STRING } },
                  link: { type: Type.STRING }
                }
              }
            },
            socialLinks: {
              type: Type.OBJECT,
              properties: {
                linkedin: { type: Type.STRING },
                github: { type: Type.STRING },
                portfolio: { type: Type.STRING }
              }
            },
            themeColor: { type: Type.STRING }
          }
        }
      }
    });

    const data = JSON.parse(response.text);
    return data as UserProfile;
  } catch (error) {
    console.error("Extraction Error:", error);
    return null;
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { AppState, Message, UserProfile, Attachment } from './types';
import { INITIAL_PROFILE, THEME_COLORS } from './constants';
import { chatWithGenie, extractProfileData } from './services/geminiService';
import ResumePreview from './components/ResumePreview';
import WebsitePreview from './components/WebsitePreview';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>('landing');
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputText, setInputText] = useState('');
  const [profile, setProfile] = useState<UserProfile>(INITIAL_PROFILE);
  const [isTyping, setIsTyping] = useState(false);
  const [previewTab, setPreviewTab] = useState<'resume' | 'website'>('resume');
  const [thinkingMode, setThinkingMode] = useState(false);
  const [pendingAttachments, setPendingAttachments] = useState<Attachment[]>([]);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Load state from memory (localStorage)
  useEffect(() => {
    const savedMessages = localStorage.getItem('pg_messages');
    const savedProfile = localStorage.getItem('pg_profile');
    const savedAppState = localStorage.getItem('pg_appstate');

    if (savedMessages) setMessages(JSON.parse(savedMessages));
    if (savedProfile) setProfile(JSON.parse(savedProfile));
    if (savedAppState) setAppState(JSON.parse(savedAppState) as AppState);
  }, []);

  // Save state to memory
  useEffect(() => {
    if (messages.length > 0) {
      localStorage.setItem('pg_messages', JSON.stringify(messages));
      localStorage.setItem('pg_profile', JSON.stringify(profile));
      localStorage.setItem('pg_appstate', JSON.stringify(appState));
    }
  }, [messages, profile, appState]);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isTyping]);

  const startInterview = async () => {
    setAppState('chatting');
    setIsTyping(true);
    const initialGreeting: Message = { 
      role: 'assistant', 
      content: "Hello! I'm PortfolioGenie. I'm here to help you build a stunning resume and a personal website. Let's start with the basics—what is your full name and what role are you targeting (e.g., Software Engineer, Marketing Manager)? You can also upload your current resume as an image or video if you want me to analyze it!" 
    };
    setMessages([initialGreeting]);
    setIsTyping(false);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files) return;

    Array.from(files).forEach(file => {
      const reader = new FileReader();
      reader.onload = (event) => {
        const base64 = (event.target?.result as string).split(',')[1];
        setPendingAttachments(prev => [...prev, {
          mimeType: file.type,
          data: base64,
          name: file.name
        }]);
      };
      reader.readAsDataURL(file);
    });
  };

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if ((!inputText.trim() && pendingAttachments.length === 0) || isTyping) return;

    const userMsg: Message = { 
      role: 'user', 
      content: inputText || (pendingAttachments.length > 0 ? "Analyze this file." : ""),
      attachments: pendingAttachments 
    };

    setMessages(prev => [...prev, userMsg]);
    setInputText('');
    setPendingAttachments([]);
    setIsTyping(true);

    try {
      const result = await chatWithGenie([...messages, userMsg], { 
        thinkingMode, 
        attachments: userMsg.attachments 
      });
      setMessages(prev => [...prev, { 
        role: 'assistant', 
        content: result.text,
        sources: result.sources
      }]);
    } catch (err) {
      console.error(err);
    } finally {
      setIsTyping(false);
    }
  };

  const generatePreview = async () => {
    setIsTyping(true);
    const data = await extractProfileData(messages);
    if (data) {
      setProfile(prev => ({ ...data, themeColor: prev.themeColor }));
      setAppState('preview');
    }
    setIsTyping(false);
  };

  const clearMemory = () => {
    if (confirm("Clear all progress and start over?")) {
      localStorage.removeItem('pg_messages');
      localStorage.removeItem('pg_profile');
      localStorage.removeItem('pg_appstate');
      window.location.reload();
    }
  };

  if (appState === 'landing') {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-900 text-white p-6 overflow-hidden relative">
        <div className="absolute top-0 left-0 w-full h-full bg-[radial-gradient(circle_at_top_right,rgba(79,70,229,0.15),transparent)] pointer-events-none"></div>
        <div className="max-w-4xl text-center z-10">
          <div className="mb-6 inline-block px-4 py-1.5 bg-indigo-500/10 border border-indigo-500/20 rounded-full text-indigo-400 text-sm font-bold tracking-widest uppercase">
            Powered by Gemini 3 Pro
          </div>
          <h1 className="text-6xl md:text-8xl font-serif font-bold mb-8 leading-tight tracking-tighter">
            Elevate your <span className="italic bg-clip-text text-transparent bg-gradient-to-r from-indigo-400 to-cyan-300">professional</span> story.
          </h1>
          <p className="text-xl text-slate-400 mb-12 max-w-2xl mx-auto leading-relaxed">
            PortfolioGenie uses vision, search, and deep reasoning to craft a high-performance resume and website in minutes. 
          </p>
          <button 
            onClick={startInterview}
            className="group px-10 py-5 bg-white text-slate-900 text-xl font-bold rounded-full hover:bg-indigo-50 transition-all flex items-center gap-4 mx-auto shadow-2xl shadow-indigo-500/20"
          >
            Start My Journey
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 group-hover:translate-x-1 transition-transform" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14 5l7 7m0 0l-7 7m7-7H3" />
            </svg>
          </button>
        </div>
      </div>
    );
  }

  if (appState === 'chatting') {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col">
        <header className="bg-white border-b px-8 py-4 flex justify-between items-center sticky top-0 z-20">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white font-black text-xl">P</div>
            <div>
              <h2 className="font-bold text-slate-900 leading-none">PortfolioGenie</h2>
              <span className="text-[10px] text-slate-400 uppercase tracking-widest font-black">Memory Enabled • Deep Thinking</span>
            </div>
          </div>
          <div className="flex items-center gap-4">
