                </svg>
                Print/PDF
             </button>
          </div>
        </header>
        <main className="flex-1 overflow-y-auto p-8 flex justify-center">
          {previewTab === 'resume' ? <ResumePreview profile={profile} /> : <div className="w-full max-w-[1200px] shadow-2xl rounded-2xl overflow-hidden border border-slate-200 bg-white"><WebsitePreview profile={profile} /></div>}
        </main>
      </div>
    );
  }

  return null;
};

