        <div className="absolute top-0 left-0 w-full h-full bg-[radial-gradient(circle_at_top_right,rgba(79,70,229,0.15),transparent)] pointer-events-none"></div>
        <div className="max-w-4xl text-center z-10">
          <div className="mb-6 inline-block px-4 py-1.5 bg-indigo-500/10 border border-indigo-500/20 rounded-full text-indigo-400 text-sm font-bold tracking-widest uppercase">
            Powered by Gemini 3 Pro
          </div>
          <h1 className="text-6xl md:text-8xl font-serif font-bold mb-8 leading-tight tracking-tighter">
            Elevate your <span className="italic bg-clip-text text-transparent bg-gradient-to-r from-indigo-400 to-cyan-300">professional</span> story.
          </h1>
          <p className="text-xl text-slate-400 mb-12 max-w-2xl mx-auto leading-relaxed">
            PortfolioGenie uses vision, search, and deep reasoning to craft a high-performance resume and website in minutes. 
          </p>
          <button 
            onClick={startInterview}
            className="group px-10 py-5 bg-white text-slate-900 text-xl font-bold rounded-full hover:bg-indigo-50 transition-all flex items-center gap-4 mx-auto shadow-2xl shadow-indigo-500/20"
          >
            Start My Journey
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 group-hover:translate-x-1 transition-transform" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14 5l7 7m0 0l-7 7m7-7H3" />
            </svg>
          </button>
        </div>
      </div>
    );
  }

  if (appState === 'chatting') {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col">
        <header className="bg-white border-b px-8 py-4 flex justify-between items-center sticky top-0 z-20">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white font-black text-xl">P</div>
            <div>
              <h2 className="font-bold text-slate-900 leading-none">PortfolioGenie</h2>
              <span className="text-[10px] text-slate-400 uppercase tracking-widest font-black">Memory Enabled • Deep Thinking</span>
            </div>
          </div>
          <div className="flex items-center gap-4">
            <button 
              onClick={clearMemory}
              className="px-4 py-2 text-slate-400 hover:text-rose-500 transition-colors text-sm font-bold"
            >
              Reset
            </button>
            <button 
              onClick={generatePreview}
              className="px-6 py-2.5 bg-indigo-600 text-white rounded-lg font-bold hover:bg-indigo-700 transition-colors shadow-lg shadow-indigo-600/10"
              disabled={messages.length < 2 || isTyping}
            >
              Generate Magic
            </button>
          </div>
        </header>

        <main className="flex-1 flex flex-col max-w-4xl mx-auto w-full p-4 overflow-y-auto pt-12 pb-32">
          {messages.map((m, i) => (
            <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'} mb-8`}>
              <div className={`max-w-[85%] rounded-3xl p-6 ${m.role === 'user' ? 'bg-indigo-600 text-white rounded-tr-none' : 'bg-white text-slate-800 rounded-tl-none shadow-sm border border-slate-100'}`}>
                {m.attachments && m.attachments.length > 0 && (
                  <div className="flex flex-wrap gap-2 mb-4">
                    {m.attachments.map((att, idx) => (
                      <div key={idx} className="bg-slate-900/10 p-2 rounded-lg text-xs flex items-center gap-2">
                        {att.mimeType.startsWith('image/') ? (
                          <img src={`data:${att.mimeType};base64,${att.data}`} className="w-12 h-12 object-cover rounded" alt="upload" />
                        ) : (
                          <div className="w-12 h-12 bg-indigo-500 rounded flex items-center justify-center text-white">FILE</div>
                        )}
                        <span className="max-w-[100px] truncate">{att.name}</span>
                      </div>
                    ))}
                  </div>
                )}
                <p className="text-lg leading-relaxed whitespace-pre-wrap">{m.content}</p>
                {m.sources && m.sources.length > 0 && (
                  <div className="mt-4 pt-4 border-t border-slate-100 flex flex-wrap gap-2">
                    {m.sources.map((src, sIdx) => (
                      <a 
                        key={sIdx} 
                        href={src.uri} 
                        target="_blank" 
                        rel="noreferrer"
                        className="text-[10px] bg-indigo-50 text-indigo-600 px-2 py-1 rounded hover:bg-indigo-100 transition-colors flex items-center gap-1"
                      >
                        <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
                        </svg>
                        {src.title}
                      </a>
                    ))}
                  </div>
                )}
              </div>
            </div>
          ))}
          {isTyping && (
            <div className="flex justify-start mb-8 animate-pulse">
              <div className="bg-white p-4 rounded-3xl rounded-tl-none shadow-sm border border-slate-100 flex gap-2 items-center">
                <span className="text-xs font-bold text-indigo-400 uppercase tracking-widest">{thinkingMode ? 'Deep Reasoning...' : 'Thinking...'}</span>
                <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce"></div>
                <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce delay-150"></div>
                <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce delay-300"></div>
              </div>
            </div>
          )}
          <div ref={messagesEndRef} />
        </main>

        <footer className="bg-white/80 backdrop-blur-md border-t p-6 sticky bottom-0 z-20">
          <div className="max-w-4xl mx-auto mb-4 flex items-center justify-between">
            <div className="flex gap-4">
              <button 
                type="button"
                onClick={() => fileInputRef.current?.click()}
                className="flex items-center gap-2 text-slate-500 hover:text-indigo-600 transition-colors text-sm font-bold"
              >
                <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.172 7l-6.586 6.586a2 2 0 102.828 2.828l6.414-6.586a4 4 0 00-5.656-5.656l-6.415 6.585a6 6 0 108.486 8.486L20.5 13" />
                </svg>
                Attach Photo/Video
              </button>
              <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" multiple accept="image/*,video/*" />
            </div>

            <div className="flex items-center gap-2">
              <span className={`text-xs font-bold uppercase tracking-widest ${thinkingMode ? 'text-indigo-600' : 'text-slate-400'}`}>Deep Thinking</span>
              <button 
                onClick={() => setThinkingMode(!thinkingMode)}
                className={`w-10 h-5 rounded-full transition-colors relative ${thinkingMode ? 'bg-indigo-600' : 'bg-slate-300'}`}
              >
                <div className={`absolute top-1 w-3 h-3 bg-white rounded-full transition-all ${thinkingMode ? 'left-6' : 'left-1'}`}></div>
              </button>
            </div>
          </div>

          {pendingAttachments.length > 0 && (
            <div className="max-w-4xl mx-auto mb-4 flex flex-wrap gap-2">
              {pendingAttachments.map((att, i) => (
                <div key={i} className="bg-indigo-50 border border-indigo-100 rounded-lg px-3 py-1 text-xs flex items-center gap-2 text-indigo-600">
                  {att.name}
                  <button onClick={() => setPendingAttachments(prev => prev.filter((_, idx) => idx !== i))} className="hover:text-rose-500 font-bold">×</button>
                </div>
              ))}
            </div>
          )}

          <form onSubmit={handleSendMessage} className="max-w-4xl mx-auto flex gap-4">
            <input 
              type="text" 
              value={inputText}
              onChange={(e) => setInputText(e.target.value)}
              placeholder={thinkingMode ? "Ask a complex question..." : "Tell Genie about your experiences..."}
              className="flex-1 bg-slate-100 border-none rounded-2xl px-6 py-4 focus:ring-2 focus:ring-indigo-500 outline-none text-lg"
              disabled={isTyping}
            />
            <button 
              type="submit"
              className="w-14 h-14 bg-indigo-600 text-white rounded-2xl flex items-center justify-center hover:bg-indigo-700 transition-colors disabled:opacity-50"
              disabled={(!inputText.trim() && pendingAttachments.length === 0) || isTyping}
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" />
              </svg>
            </button>
          </form>
        </footer>
      </div>
    );
  }

  if (appState === 'preview') {
    return (
      <div className="min-h-screen bg-slate-100 flex flex-col">
        {/* Toast Notification */}
        {showShareToast && (
          <div className="fixed top-24 left-1/2 -translate-x-1/2 bg-slate-900 text-white px-6 py-3 rounded-full shadow-2xl z-[100] animate-bounce font-bold">
            Link copied to clipboard! 🚀
          </div>
        )}

        <header className="bg-white border-b px-8 py-4 flex justify-between items-center sticky top-0 z-30 no-print">
          <div className="flex items-center gap-6">
             <button onClick={() => setAppState('chatting')} className="text-slate-400 hover:text-slate-900 transition-colors" title="Back to Chat">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" />
                </svg>
             </button>
             <div className="h-6 w-px bg-slate-200"></div>
             <div className="flex bg-slate-100 p-1 rounded-xl">
                <button onClick={() => setPreviewTab('resume')} className={`px-4 py-1.5 rounded-lg text-sm font-bold transition-all ${previewTab === 'resume' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500 hover:text-slate-700'}`}>Resume</button>
                <button onClick={() => setPreviewTab('website')} className={`px-4 py-1.5 rounded-lg text-sm font-bold transition-all ${previewTab === 'website' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500 hover:text-slate-700'}`}>Website</button>
             </div>
          </div>
          <div className="flex items-center gap-4">
             {previewTab === 'website' && (
                <div className="flex gap-2 mr-4">
                   {THEME_COLORS.map(c => (
                     <button key={c.name} onClick={() => setProfile(p => ({ ...p, themeColor: c.value }))} className={`w-6 h-6 rounded-full border-2 ${profile.themeColor === c.value ? 'border-slate-900' : 'border-transparent'}`} style={{ backgroundColor: c.value }} title={c.name} />
                   ))}
                </div>
             )}

             <button 
               onClick={handleShare}
               className="flex items-center gap-2 px-6 py-2 border-2 border-slate-200 text-slate-700 rounded-lg font-bold hover:bg-slate-50 transition-colors"
             >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.632 3.316m-6.632-6l6.632-3.316m0 0a3 3 0 105.367-2.684 3 3 0 00-5.367 2.684zm0 9.316a3 3 0 105.368 2.684 3 3 0 00-5.368-2.684z" />
                </svg>
                Share Profile
             </button>

             <button onClick={() => window.print()} className="flex items-center gap-2 px-6 py-2 bg-slate-900 text-white rounded-lg font-bold hover:bg-slate-800 transition-colors">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                </svg>
                Export PDF
             </button>
          </div>
        </header>
        <main className="flex-1 overflow-y-auto p-8 flex justify-center">
          {previewTab === 'resume' ? <ResumePreview profile={profile} /> : <div className="w-full max-w-[1200px] shadow-2xl rounded-2xl overflow-hidden border border-slate-200 bg-white"><WebsitePreview profile={profile} /></div>}
        </main>
      </div>
    );
  }

  return null;
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { AppState, Message, UserProfile, Attachment } from './types';
import { INITIAL_PROFILE, THEME_COLORS } from './constants';
import { chatWithGenie, extractProfileData } from './services/geminiService';
import ResumePreview from './components/ResumePreview';
import WebsitePreview from './components/WebsitePreview';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>('landing');
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputText, setInputText] = useState('');
  const [profile, setProfile] = useState<UserProfile>(INITIAL_PROFILE);
  const [isTyping, setIsTyping] = useState(false);
  const [previewTab, setPreviewTab] = useState<'resume' | 'website'>('resume');
  const [thinkingMode, setThinkingMode] = useState(false);
  const [pendingAttachments, setPendingAttachments] = useState<Attachment[]>([]);
  const [showShareToast, setShowShareToast] = useState(false);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Load state from memory (localStorage or Hash)
  useEffect(() => {
    // 1. Check for shared data in Hash
    const hash = window.location.hash;
    if (hash.startsWith('#share=')) {
      try {
        const encodedData = hash.replace('#share=', '');
        const decodedData = JSON.parse(decodeURIComponent(escape(atob(encodedData))));
        setProfile(decodedData);
        setAppState('preview');
        // Clear hash after loading to keep URL clean for user
        window.history.replaceState(null, '', window.location.pathname);
        return;
      } catch (e) {
        console.error("Failed to parse shared profile", e);
      }
    }

    // 2. Otherwise load from memory (localStorage)
    const savedMessages = localStorage.getItem('pg_messages');
    const savedProfile = localStorage.getItem('pg_profile');
    const savedAppState = localStorage.getItem('pg_appstate');

    if (savedMessages) setMessages(JSON.parse(savedMessages));
    if (savedProfile) setProfile(JSON.parse(savedProfile));
    if (savedAppState) setAppState(JSON.parse(savedAppState) as AppState);
  }, []);

  // Save state to memory
  useEffect(() => {
    // Only save if there is actually content to save
    if (messages.length > 0) {
      localStorage.setItem('pg_messages', JSON.stringify(messages));
      localStorage.setItem('pg_profile', JSON.stringify(profile));
      localStorage.setItem('pg_appstate', JSON.stringify(appState));
    }
  }, [messages, profile, appState]);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isTyping]);

  const startInterview = async () => {
    setAppState('chatting');
    setIsTyping(true);
    const initialGreeting: Message = { 
      role: 'assistant', 
      content: "Hello! I'm PortfolioGenie. I'm here to help you build a stunning resume and a personal website. Let's start with the basics—what is your full name and what role are you targeting (e.g., Software Engineer, Marketing Manager)? You can also upload your current resume as an image or video if you want me to analyze it!" 
    };
    setMessages([initialGreeting]);
    setIsTyping(false);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files) return;

    Array.from(files).forEach((file: File) => {
      const reader = new FileReader();
      reader.onload = (event) => {
        const base64 = (event.target?.result as string).split(',')[1];
        setPendingAttachments(prev => [...prev, {
          mimeType: file.type,
          data: base64,
          name: file.name
        }]);
      };
      reader.readAsDataURL(file);
    });
  };

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if ((!inputText.trim() && pendingAttachments.length === 0) || isTyping) return;

    const userMsg: Message = { 
      role: 'user', 
      content: inputText || (pendingAttachments.length > 0 ? "Analyze this file." : ""),
      attachments: pendingAttachments 
    };

    setMessages(prev => [...prev, userMsg]);
    setInputText('');
    setPendingAttachments([]);
    setIsTyping(true);

    try {
      const result = await chatWithGenie([...messages, userMsg], { 
        thinkingMode, 
        attachments: userMsg.attachments 
      });
      setMessages(prev => [...prev, { 
        role: 'assistant', 
        content: result.text,
        sources: result.sources
      }]);
    } catch (err) {
      console.error(err);
    } finally {
      setIsTyping(false);
    }
  };

  const generatePreview = async () => {
    setIsTyping(true);
    const data = await extractProfileData(messages);
    if (data) {
      setProfile(prev => ({ ...data, themeColor: prev.themeColor }));
      setAppState('preview');
    }
    setIsTyping(false);
  };

  const clearMemory = () => {
    if (confirm("Clear all progress and start over?")) {
      // Clear localStorage explicitly first
      localStorage.removeItem('pg_messages');
      localStorage.removeItem('pg_profile');
      localStorage.removeItem('pg_appstate');

      // Reset React state to initial values
      // This will trigger a re-render and the "Save state" useEffect 
      // will not re-save because messages.length will be 0
      setMessages([]);
      setProfile(INITIAL_PROFILE);
      setAppState('landing');
      setInputText('');
      setPendingAttachments([]);

      // Force a reload to clear any remaining memory/states
      window.location.reload();
    }
  };

  const handleShare = async () => {
    try {
      // Encode profile data into a shareable link
      const jsonStr = JSON.stringify(profile);
      const encodedData = btoa(unescape(encodeURIComponent(jsonStr)));
      const shareUrl = `${window.location.origin}${window.location.pathname}#share=${encodedData}`;

      if (navigator.share) {
        await navigator.share({
          title: `Professional Profile - ${profile.name}`,
          text: `Check out my AI-generated professional profile created with PortfolioGenie!`,
          url: shareUrl,
        });
      } else {
        await navigator.clipboard.writeText(shareUrl);
        setShowShareToast(true);
        setTimeout(() => setShowShareToast(false), 3000);
      }
    } catch (err) {
      console.error("Error sharing profile:", err);
    }
  };

  if (appState === 'landing') {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-900 text-white p-6 overflow-hidden relative">
        <div className="absolute top-0 left-0 w-full h-full bg-[radial-gradient(circle_at_top_right,rgba(79,70,229,0.15),transparent)] pointer-events-none"></div>
        <div className="max-w-4xl text-center z-10">
          <div className="mb-6 inline-block px-4 py-1.5 bg-indigo-500/10 border border-indigo-500/20 rounded-full text-indigo-400 text-sm font-bold tracking-widest uppercase">
            Powered by Gemini 3 Pro
          </div>
          <h1 className="text-6xl md:text-8xl font-serif font-bold mb-8 leading-tight tracking-tighter">
            Elevate your <span className="italic bg-clip-text text-transparent bg-gradient-to-r from-indigo-400 to-cyan-300">professional</span> story.
          </h1>
          <p className="text-xl text-slate-400 mb-12 max-w-2xl mx-auto leading-relaxed">
            PortfolioGenie uses vision, search, and deep reasoning to craft a high-performance resume and website in minutes. 
          </p>
          <button 
            onClick={startInterview}
            className="group px-10 py-5 bg-white text-slate-900 text-xl font-bold rounded-full hover:bg-indigo-50 transition-all flex items-center gap-4 mx-auto shadow-2xl shadow-indigo-500/20"
          >
            Start My Journey
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 group-hover:translate-x-1 transition-transform" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14 5l7 7m0 0l-7 7m7-7H3" />
            </svg>
          </button>
        </div>
      </div>
    );
  }

  if (appState === 'chatting') {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col">
        <header className="bg-white border-b px-8 py-4 flex justify-between items-center sticky top-0 z-20">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white font-black text-xl">P</div>
            <div>
              <h2 className="font-bold text-slate-900 leading-none">PortfolioGenie</h2>
              <span className="text-[10px] text-slate-400 uppercase tracking-widest font-black">Memory Enabled • Deep Thinking</span>
            </div>
          </div>
          <div className="flex items-center gap-4">
            <button 
              onClick={clearMemory}
              className="px-4 py-2 text-slate-400 hover:text-rose-500 transition-colors text-sm font-bold flex items-center gap-2"
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
              </svg>
              Reset
            </button>
            <button 
              onClick={generatePreview}
              className="px-6 py-2.5 bg-indigo-600 text-white rounded-lg font-bold hover:bg-indigo-700 transition-colors shadow-lg shadow-indigo-600/10"
              disabled={messages.length < 2 || isTyping}
            >
              Generate Magic
            </button>
          </div>
        </header>

        <main className="flex-1 flex flex-col max-w-4xl mx-auto w-full p-4 overflow-y-auto pt-12 pb-32">
          {messages.map((m, i) => (
            <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'} mb-8`}>
              <div className={`max-w-[85%] rounded-3xl p-6 ${m.role === 'user' ? 'bg-indigo-600 text-white rounded-tr-none' : 'bg-white text-slate-800 rounded-tl-none shadow-sm border border-slate-100'}`}>
                {m.attachments && m.attachments.length > 0 && (
                  <div className="flex flex-wrap gap-2 mb-4">
                    {m.attachments.map((att, idx) => (
                      <div key={idx} className="bg-slate-900/10 p-2 rounded-lg text-xs flex items-center gap-2">
                        {att.mimeType.startsWith('image/') ? (
                          <img src={`data:${att.mimeType};base64,${att.data}`} className="w-12 h-12 object-cover rounded" alt="upload" />
                        ) : (
                          <div className="w-12 h-12 bg-indigo-500 rounded flex items-center justify-center text-white font-bold">FILE</div>
                        )}
                        <span className="max-w-[100px] truncate">{att.name}</span>
                      </div>
                    ))}
                  </div>
                )}
                <p className="text-lg leading-relaxed whitespace-pre-wrap">{m.content}</p>
                {m.sources && m.sources.length > 0 && (
                  <div className="mt-4 pt-4 border-t border-slate-100 flex flex-wrap gap-2">
                    {m.sources.map((src, sIdx) => (
                      <a 
                        key={sIdx} 
                        href={src.uri} 
                        target="_blank" 
                        rel="noreferrer"
                        className="text-[10px] bg-indigo-50 text-indigo-600 px-2 py-1 rounded hover:bg-indigo-100 transition-colors flex items-center gap-1"
                      >
                        <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
                        </svg>
                        {src.title}
                      </a>
                    ))}
                  </div>
                )}
              </div>
            </div>
          ))}
          {isTyping && (
            <div className="flex justify-start mb-8 animate-pulse">
              <div className="bg-white p-4 rounded-3xl rounded-tl-none shadow-sm border border-slate-100 flex gap-2 items-center">
                <span className="text-xs font-bold text-indigo-400 uppercase tracking-widest">{thinkingMode ? 'Deep Reasoning...' : 'Thinking...'}</span>
                <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce"></div>
                <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce delay-150"></div>
                <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce delay-300"></div>
              </div>
            </div>
          )}
          <div ref={messagesEndRef} />
        </main>

        <footer className="bg-white/80 backdrop-blur-md border-t p-6 sticky bottom-0 z-20">
          <div className="max-w-4xl mx-auto mb-4 flex items-center justify-between">
            <div className="flex gap-4">
              <button 
                type="button"
                onClick={() => fileInputRef.current?.click()}
                className="flex items-center gap-2 text-slate-500 hover:text-indigo-600 transition-colors text-sm font-bold"
              >
                <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.172 7l-6.586 6.586a2 2 0 102.828 2.828l6.414-6.586a4 4 0 00-5.656-5.656l-6.415 6.585a6 6 0 108.486 8.486L20.5 13" />
                </svg>
                Attach Photo/Video
              </button>
              <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" multiple accept="image/*,video/*" />
            </div>

            <div className="flex items-center gap-2">
              <span className={`text-xs font-bold uppercase tracking-widest ${thinkingMode ? 'text-indigo-600' : 'text-slate-400'}`}>Deep Thinking</span>
              <button 
                onClick={() => setThinkingMode(!thinkingMode)}
                className={`w-10 h-5 rounded-full transition-colors relative ${thinkingMode ? 'bg-indigo-600' : 'bg-slate-300'}`}
              >
                <div className={`absolute top-1 w-3 h-3 bg-white rounded-full transition-all ${thinkingMode ? 'left-6' : 'left-1'}`}></div>
              </button>
            </div>
          </div>

          {pendingAttachments.length > 0 && (
            <div className="max-w-4xl mx-auto mb-4 flex flex-wrap gap-2">
              {pendingAttachments.map((att, i) => (
                <div key={i} className="bg-indigo-50 border border-indigo-100 rounded-lg px-3 py-1 text-xs flex items-center gap-2 text-indigo-600">
                  {att.name}
                  <button onClick={() => setPendingAttachments(prev => prev.filter((_, idx) => idx !== i))} className="hover:text-rose-500 font-bold">×</button>
                </div>
              ))}
            </div>
          )}

          <form onSubmit={handleSendMessage} className="max-w-4xl mx-auto flex gap-4">
            <input 
              type="text" 
              value={inputText}
              onChange={(e) => setInputText(e.target.value)}
              placeholder={thinkingMode ? "Ask a complex question..." : "Tell Genie about your experiences..."}
              className="flex-1 bg-slate-100 border-none rounded-2xl px-6 py-4 focus:ring-2 focus:ring-indigo-500 outline-none text-lg"
              disabled={isTyping}
            />
            <button 
              type="submit"
              className="w-14 h-14 bg-indigo-600 text-white rounded-2xl flex items-center justify-center hover:bg-indigo-700 transition-colors disabled:opacity-50"
              disabled={(!inputText.trim() && pendingAttachments.length === 0) || isTyping}
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" />
              </svg>
            </button>
          </form>
        </footer>
      </div>
    );
  }

  if (appState === 'preview') {
    return (
      <div className="min-h-screen bg-slate-100 flex flex-col">
        {/* Toast Notification */}
        {showShareToast && (
          <div className="fixed top-24 left-1/2 -translate-x-1/2 bg-slate-900 text-white px-6 py-3 rounded-full shadow-2xl z-[100] animate-bounce font-bold">
            Link copied to clipboard! 🚀
          </div>
        )}

        <header className="bg-white border-b px-8 py-4 flex justify-between items-center sticky top-0 z-30 no-print">
          <div className="flex items-center gap-6">
             <button onClick={() => setAppState('chatting')} className="text-slate-400 hover:text-slate-900 transition-colors" title="Back to Chat">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" />
                </svg>
             </button>
             <div className="h-6 w-px bg-slate-200"></div>
             <div className="flex bg-slate-100 p-1 rounded-xl">
                <button onClick={() => setPreviewTab('resume')} className={`px-4 py-1.5 rounded-lg text-sm font-bold transition-all ${previewTab === 'resume' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500 hover:text-slate-700'}`}>Resume</button>
                <button onClick={() => setPreviewTab('website')} className={`px-4 py-1.5 rounded-lg text-sm font-bold transition-all ${previewTab === 'website' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500 hover:text-slate-700'}`}>Website</button>
             </div>
          </div>
          <div className="flex items-center gap-4">
             {previewTab === 'website' && (
                <div className="flex gap-2 mr-4">
                   {THEME_COLORS.map(c => (
                     <button key={c.name} onClick={() => setProfile(p => ({ ...p, themeColor: c.value }))} className={`w-6 h-6 rounded-full border-2 ${profile.themeColor === c.value ? 'border-slate-900' : 'border-transparent'}`} style={{ backgroundColor: c.value }} title={c.name} />
                   ))}
                </div>
             )}

             <button 
               onClick={handleShare}
               className="flex items-center gap-2 px-6 py-2 border-2 border-slate-200 text-slate-700 rounded-lg font-bold hover:bg-slate-50 transition-colors"
             >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.632 3.316m-6.632-6l6.632-3.316m0 0a3 3 0 105.367-2.684 3 3 0 00-5.367 2.684zm0 9.316a3 3 0 105.368 2.684 3 3 0 00-5.368-2.684z" />
                </svg>
                Share Profile
             </button>

             <button onClick={() => window.print()} className="flex items-center gap-2 px-6 py-2 bg-slate-900 text-white rounded-lg font-bold hover:bg-slate-800 transition-colors">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                </svg>
                Export PDF
             </button>
          </div>
        </header>
        <main className="flex-1 overflow-y-auto p-8 flex justify-center">
          {previewTab === 'resume' ? <ResumePreview profile={profile} /> : <div className="w-full max-w-[1200px] shadow-2xl rounded-2xl overflow-hidden border border-slate-200 bg-white"><WebsitePreview profile={profile} /></div>}
        </main>
      </div>
    );
  }

  return null;
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { AppState, Message, UserProfile, Attachment } from './types';
import { INITIAL_PROFILE, THEME_COLORS } from './constants';
import { chatWithGenie, extractProfileData } from './services/geminiService';
import ResumePreview from './components/ResumePreview';
import WebsitePreview from './components/WebsitePreview';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>('landing');
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputText, setInputText] = useState('');
  const [profile, setProfile] = useState<UserProfile>(INITIAL_PROFILE);
  const [isTyping, setIsTyping] = useState(false);
  const [previewTab, setPreviewTab] = useState<'resume' | 'website'>('resume');
  const [thinkingMode, setThinkingMode] = useState(false);
  const [pendingAttachments, setPendingAttachments] = useState<Attachment[]>([]);
  const [showShareToast, setShowShareToast] = useState(false);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Load state from memory (localStorage or Hash)
  useEffect(() => {
    // 1. Check for shared data in Hash
    const hash = window.location.hash;
    if (hash.startsWith('#share=')) {
      try {
        const encodedData = hash.replace('#share=', '');
        const decodedData = JSON.parse(decodeURIComponent(escape(atob(encodedData))));
        setProfile(decodedData);
        setAppState('preview');
        // Clear hash after loading to keep URL clean for user
        window.history.replaceState(null, '', window.location.pathname);
        return;
      } catch (e) {
        console.error("Failed to parse shared profile", e);
      }
    }

    // 2. Otherwise load from memory (localStorage)
    const savedMessages = localStorage.getItem('pg_messages');
    const savedProfile = localStorage.getItem('pg_profile');
    const savedAppState = localStorage.getItem('pg_appstate');

    if (savedMessages) setMessages(JSON.parse(savedMessages));
    if (savedProfile) setProfile(JSON.parse(savedProfile));
    if (savedAppState) setAppState(JSON.parse(savedAppState) as AppState);
  }, []);

  // Save state to memory
  useEffect(() => {
    // Only save if there is actually content to save
    if (messages.length > 0) {
      localStorage.setItem('pg_messages', JSON.stringify(messages));
      localStorage.setItem('pg_profile', JSON.stringify(profile));
      localStorage.setItem('pg_appstate', JSON.stringify(appState));
    }
  }, [messages, profile, appState]);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isTyping]);

  const startInterview = async () => {
    setAppState('chatting');
    setIsTyping(true);
    const initialGreeting: Message = { 
      role: 'assistant', 
      content: "Hello! I'm PortfolioGenie. I'm here to help you build a stunning resume and a personal website. Let's start with the basics—what is your full name and what role are you targeting (e.g., Software Engineer, Marketing Manager)? You can also upload your current resume as an image or video if you want me to analyze it!" 
    };
    setMessages([initialGreeting]);
    setIsTyping(false);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files) return;

    Array.from(files).forEach((file: File) => {
      const reader = new FileReader();
      reader.onload = (event) => {
        const base64 = (event.target?.result as string).split(',')[1];
        setPendingAttachments(prev => [...prev, {
          mimeType: file.type,
          data: base64,
          name: file.name
        }]);
      };
      reader.readAsDataURL(file);
    });
  };

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if ((!inputText.trim() && pendingAttachments.length === 0) || isTyping) return;

    const userMsg: Message = { 
      role: 'user', 
      content: inputText || (pendingAttachments.length > 0 ? "Analyze this file." : ""),
      attachments: pendingAttachments 
    };

    setMessages(prev => [...prev, userMsg]);
    setInputText('');
    setPendingAttachments([]);
    setIsTyping(true);

    try {
      const result = await chatWithGenie([...messages, userMsg], { 
        thinkingMode, 
        attachments: userMsg.attachments 
      });
      setMessages(prev => [...prev, { 
        role: 'assistant', 
        content: result.text,
        sources: result.sources
      }]);
    } catch (err) {
      console.error(err);
    } finally {
      setIsTyping(false);
    }
  };

  const generatePreview = async () => {
    setIsTyping(true);
    const data = await extractProfileData(messages);
    if (data) {
      setProfile(prev => ({ ...data, themeColor: prev.themeColor }));
      setAppState('preview');
    }
    setIsTyping(false);
  };

  const clearMemory = () => {
    if (confirm("Clear all progress and start over?")) {
      localStorage.removeItem('pg_messages');
      localStorage.removeItem('pg_profile');
      localStorage.removeItem('pg_appstate');
      setMessages([]);
      setProfile(INITIAL_PROFILE);
      setAppState('landing');
      setInputText('');
      setPendingAttachments([]);
      window.location.reload();
    }
  };

  const handleShare = async () => {
    try {
      const jsonStr = JSON.stringify(profile);
      const encodedData = btoa(unescape(encodeURIComponent(jsonStr)));
      const shareUrl = `${window.location.origin}${window.location.pathname}#share=${encodedData}`;

      if (navigator.share) {
        await navigator.share({
          title: `Professional Profile - ${profile.name}`,
          text: `Check out my AI-generated professional profile created with PortfolioGenie!`,
          url: shareUrl,
        });
      } else {
        await navigator.clipboard.writeText(shareUrl);
        setShowShareToast(true);
        setTimeout(() => setShowShareToast(false), 3000);
      }
    } catch (err) {
      console.error("Error sharing profile:", err);
    }
  };

  const exportAsHTML = () => {
    const isResume = previewTab === 'resume';
    const fileName = `${profile.name || 'portfolio'}-${previewTab}.html`;

    // Simple HTML template builder
    const htmlContent = `
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>${profile.name || 'Portfolio'} - ${previewTab.toUpperCase()}</title>
    <script src="https://cdn.tailwindcss.com"></script>
    <link rel="preconnect" href="https://fonts.googleapis.com">
    <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
    <link href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&family=Playfair+Display:wght@700&display=swap" rel="stylesheet">
    <style>
        body { font-family: 'Inter', sans-serif; }
        .font-serif { font-family: 'Playfair Display', serif; }
    </style>
</head>
<body class="bg-slate-50">
    <div id="content-mount">
        ${document.querySelector(isResume ? '#resume-container' : 'main > div')?.outerHTML || 'Content missing'}
    </div>
</body>
</html>`;

    const blob = new Blob([htmlContent], { type: 'text/html' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = fileName;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  if (appState === 'landing') {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-900 text-white p-6 overflow-hidden relative">
        <div className="absolute top-0 left-0 w-full h-full bg-[radial-gradient(circle_at_top_right,rgba(79,70,229,0.15),transparent)] pointer-events-none"></div>
        <div className="max-w-4xl text-center z-10">
          <div className="mb-6 inline-block px-4 py-1.5 bg-indigo-500/10 border border-indigo-500/20 rounded-full text-indigo-400 text-sm font-bold tracking-widest uppercase">
            Powered by Gemini 3 Pro
          </div>
          <h1 className="text-6xl md:text-8xl font-serif font-bold mb-8 leading-tight tracking-tighter">
            Elevate your <span className="italic bg-clip-text text-transparent bg-gradient-to-r from-indigo-400 to-cyan-300">professional</span> story.
          </h1>
          <p className="text-xl text-slate-400 mb-12 max-w-2xl mx-auto leading-relaxed">
            PortfolioGenie uses vision, search, and deep reasoning to craft a high-performance resume and website in minutes. 
          </p>
          <button 
            onClick={startInterview}
            className="group px-10 py-5 bg-white text-slate-900 text-xl font-bold rounded-full hover:bg-indigo-50 transition-all flex items-center gap-4 mx-auto shadow-2xl shadow-indigo-500/20"
          >
            Start My Journey
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 group-hover:translate-x-1 transition-transform" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14 5l7 7m0 0l-7 7m7-7H3" />
            </svg>
          </button>
        </div>
      </div>
    );
  }

  if (appState === 'chatting') {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col">
        <header className="bg-white border-b px-8 py-4 flex justify-between items-center sticky top-0 z-20">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white font-black text-xl">P</div>
            <div>
              <h2 className="font-bold text-slate-900 leading-none">PortfolioGenie</h2>
              <span className="text-[10px] text-slate-400 uppercase tracking-widest font-black">Memory Enabled • Deep Thinking</span>
            </div>
          </div>
          <div className="flex items-center gap-4">
            <button 
              onClick={clearMemory}
              className="px-4 py-2 text-slate-400 hover:text-rose-500 transition-colors text-sm font-bold flex items-center gap-2"
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
              </svg>
              Reset
            </button>
            <button 
              onClick={generatePreview}
              className="px-6 py-2.5 bg-indigo-600 text-white rounded-lg font-bold hover:bg-indigo-700 transition-colors shadow-lg shadow-indigo-600/10"
              disabled={messages.length < 2 || isTyping}
            >
              Generate Magic
            </button>
          </div>
        </header>

        <main className="flex-1 flex flex-col max-w-4xl mx-auto w-full p-4 overflow-y-auto pt-12 pb-32">
          {messages.map((m, i) => (
            <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'} mb-8`}>
              <div className={`max-w-[85%] rounded-3xl p-6 ${m.role === 'user' ? 'bg-indigo-600 text-white rounded-tr-none' : 'bg-white text-slate-800 rounded-tl-none shadow-sm border border-slate-100'}`}>
                {m.attachments && m.attachments.length > 0 && (
                  <div className="flex flex-wrap gap-2 mb-4">
                    {m.attachments.map((att, idx) => (
                      <div key={idx} className="bg-slate-900/10 p-2 rounded-lg text-xs flex items-center gap-2">
                        {att.mimeType.startsWith('image/') ? (
                          <img src={`data:${att.mimeType};base64,${att.data}`} className="w-12 h-12 object-cover rounded" alt="upload" />
                        ) : (
                          <div className="w-12 h-12 bg-indigo-500 rounded flex items-center justify-center text-white font-bold">FILE</div>
                        )}
                        <span className="max-w-[100px] truncate">{att.name}</span>
                      </div>
                    ))}
                  </div>
                )}
                <p className="text-lg leading-relaxed whitespace-pre-wrap">{m.content}</p>
                {m.sources && m.sources.length > 0 && (
                  <div className="mt-4 pt-4 border-t border-slate-100 flex flex-wrap gap-2">
                    {m.sources.map((src, sIdx) => (
                      <a 
                        key={sIdx} 
                        href={src.uri} 
                        target="_blank" 
                        rel="noreferrer"
                        className="text-[10px] bg-indigo-50 text-indigo-600 px-2 py-1 rounded hover:bg-indigo-100 transition-colors flex items-center gap-1"
                      >
                        <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
                        </svg>
                        {src.title}
                      </a>
                    ))}
                  </div>
                )}
              </div>
            </div>
          ))}
          {isTyping && (
            <div className="flex justify-start mb-8 animate-pulse">
              <div className="bg-white p-4 rounded-3xl rounded-tl-none shadow-sm border border-slate-100 flex gap-2 items-center">
                <span className="text-xs font-bold text-indigo-400 uppercase tracking-widest">{thinkingMode ? 'Deep Reasoning...' : 'Thinking...'}</span>
                <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce"></div>
                <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce delay-150"></div>
                <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce delay-300"></div>
              </div>
            </div>
          )}
          <div ref={messagesEndRef} />
        </main>

        <footer className="bg-white/80 backdrop-blur-md border-t p-6 sticky bottom-0 z-20">
          <div className="max-w-4xl mx-auto mb-4 flex items-center justify-between">
            <div className="flex gap-4">
              <button 
                type="button"
                onClick={() => fileInputRef.current?.click()}
                className="flex items-center gap-2 text-slate-500 hover:text-indigo-600 transition-colors text-sm font-bold"
              >
                <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.172 7l-6.586 6.586a2 2 0 102.828 2.828l6.414-6.586a4 4 0 00-5.656-5.656l-6.415 6.585a6 6 0 108.486 8.486L20.5 13" />
                </svg>
                Attach Photo/Video
              </button>
              <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" multiple accept="image/*,video/*" />
            </div>

            <div className="flex items-center gap-2">
              <span className={`text-xs font-bold uppercase tracking-widest ${thinkingMode ? 'text-indigo-600' : 'text-slate-400'}`}>Deep Thinking</span>
              <button 
                onClick={() => setThinkingMode(!thinkingMode)}
                className={`w-10 h-5 rounded-full transition-colors relative ${thinkingMode ? 'bg-indigo-600' : 'bg-slate-300'}`}
              >
                <div className={`absolute top-1 w-3 h-3 bg-white rounded-full transition-all ${thinkingMode ? 'left-6' : 'left-1'}`}></div>
              </button>
            </div>
          </div>

          {pendingAttachments.length > 0 && (
            <div className="max-w-4xl mx-auto mb-4 flex flex-wrap gap-2">
              {pendingAttachments.map((att, i) => (
                <div key={i} className="bg-indigo-50 border border-indigo-100 rounded-lg px-3 py-1 text-xs flex items-center gap-2 text-indigo-600">
                  {att.name}
                  <button onClick={() => setPendingAttachments(prev => prev.filter((_, idx) => idx !== i))} className="hover:text-rose-500 font-bold">×</button>
                </div>
              ))}
            </div>
          )}

          <form onSubmit={handleSendMessage} className="max-w-4xl mx-auto flex gap-4">
            <input 
              type="text" 
              value={inputText}
              onChange={(e) => setInputText(e.target.value)}
              placeholder={thinkingMode ? "Ask a complex question..." : "Tell Genie about your experiences..."}
              className="flex-1 bg-slate-100 border-none rounded-2xl px-6 py-4 focus:ring-2 focus:ring-indigo-500 outline-none text-lg"
              disabled={isTyping}
            />
            <button 
              type="submit"
              className="w-14 h-14 bg-indigo-600 text-white rounded-2xl flex items-center justify-center hover:bg-indigo-700 transition-colors disabled:opacity-50"
              disabled={(!inputText.trim() && pendingAttachments.length === 0) || isTyping}
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" />
              </svg>
            </button>
          </form>
        </footer>
      </div>
    );
  }

  if (appState === 'preview') {
    return (
      <div className="min-h-screen bg-slate-100 flex flex-col">
        {/* Toast Notification */}
        {showShareToast && (
          <div className="fixed top-24 left-1/2 -translate-x-1/2 bg-slate-900 text-white px-6 py-3 rounded-full shadow-2xl z-[100] animate-bounce font-bold">
            Link copied to clipboard! 🚀
          </div>
        )}

        <header className="bg-white border-b px-8 py-4 flex justify-between items-center sticky top-0 z-30 no-print overflow-x-auto">
          <div className="flex items-center gap-6 shrink-0">
             <button onClick={() => setAppState('chatting')} className="text-slate-400 hover:text-slate-900 transition-colors" title="Back to Chat">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" />
                </svg>
             </button>
             <div className="h-6 w-px bg-slate-200"></div>
             <div className="flex bg-slate-100 p-1 rounded-xl">
                <button onClick={() => setPreviewTab('resume')} className={`px-4 py-1.5 rounded-lg text-sm font-bold transition-all ${previewTab === 'resume' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500 hover:text-slate-700'}`}>Resume</button>
                <button onClick={() => setPreviewTab('website')} className={`px-4 py-1.5 rounded-lg text-sm font-bold transition-all ${previewTab === 'website' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500 hover:text-slate-700'}`}>Website</button>
             </div>
          </div>
          <div className="flex items-center gap-4 shrink-0">
             {previewTab === 'website' && (
                <div className="flex gap-2 mr-4 hidden md:flex">
                   {THEME_COLORS.map(c => (
                     <button key={c.name} onClick={() => setProfile(p => ({ ...p, themeColor: c.value }))} className={`w-6 h-6 rounded-full border-2 ${profile.themeColor === c.value ? 'border-slate-900' : 'border-transparent'}`} style={{ backgroundColor: c.value }} title={c.name} />
                   ))}
                </div>
             )}

             <button 
               onClick={handleShare}
               className="flex items-center gap-2 px-4 py-2 border-2 border-slate-200 text-slate-700 rounded-lg font-bold hover:bg-slate-50 transition-colors text-sm"
             >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.632 3.316m-6.632-6l6.632-3.316m0 0a3 3 0 105.367-2.684 3 3 0 00-5.367 2.684zm0 9.316a3 3 0 105.368 2.684 3 3 0 00-5.368-2.684z" />
                </svg>
                Share
             </button>

             <div className="flex gap-2 bg-slate-900 rounded-lg p-1">
                <button onClick={() => window.print()} className="flex items-center gap-2 px-4 py-1.5 text-white rounded-md font-bold hover:bg-slate-800 transition-colors text-sm" title="Print as PDF">
                   <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                     <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 21h10a2 2 0 002-2V9.414a1 1 0 00-.293-.707l-5.414-5.414A1 1 0 0012.586 3H7a2 2 0 00-2 2v14a2 2 0 002 2z" />
                   </svg>
                   PDF
                </button>
                <div className="w-px bg-slate-700 self-stretch my-1"></div>
                <button onClick={exportAsHTML} className="flex items-center gap-2 px-4 py-1.5 text-white rounded-md font-bold hover:bg-slate-800 transition-colors text-sm" title="Download as HTML">
                   <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                     <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 20l4-16m4 4l4 4-4 4M6 16l-4-4 4-4" />
                   </svg>
                   HTML
                </button>
             </div>
          </div>
        </header>
        <main className="flex-1 overflow-y-auto p-8 flex justify-center">
          {previewTab === 'resume' ? <ResumePreview profile={profile} /> : <div className="w-full max-w-[1200px] shadow-2xl rounded-2xl overflow-hidden border border-slate-200 bg-white"><WebsitePreview profile={profile} /></div>}
        </main>
      </div>
    );
  }

  return null;
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { AppState, Message, UserProfile, Attachment } from './types';
import { INITIAL_PROFILE, THEME_COLORS } from './constants';
import { chatWithGenie, extractProfileData } from './services/geminiService';
import ResumePreview from './components/ResumePreview';
import WebsitePreview from './components/WebsitePreview';

// Declare html2pdf for TypeScript
declare var html2pdf: any;

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>('landing');
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputText, setInputText] = useState('');
  const [profile, setProfile] = useState<UserProfile>(INITIAL_PROFILE);
  const [isTyping, setIsTyping] = useState(false);
  const [previewTab, setPreviewTab] = useState<'resume' | 'website'>('resume');
  const [thinkingMode, setThinkingMode] = useState(false);
  const [pendingAttachments, setPendingAttachments] = useState<Attachment[]>([]);
  const [showShareToast, setShowShareToast] = useState(false);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Load state from memory (localStorage or Hash)
  useEffect(() => {
    // 1. Check for shared data in Hash
    const hash = window.location.hash;
    if (hash.startsWith('#share=')) {
      try {
        const encodedData = hash.replace('#share=', '');
        const decodedData = JSON.parse(decodeURIComponent(escape(atob(encodedData))));
        setProfile(decodedData);
        setAppState('preview');
        // Clear hash after loading to keep URL clean for user
        window.history.replaceState(null, '', window.location.pathname);
        return;
      } catch (e) {
        console.error("Failed to parse shared profile", e);
      }
    }

    // 2. Otherwise load from memory (localStorage)
    const savedMessages = localStorage.getItem('pg_messages');
    const savedProfile = localStorage.getItem('pg_profile');
    const savedAppState = localStorage.getItem('pg_appstate');

    if (savedMessages) setMessages(JSON.parse(savedMessages));
    if (savedProfile) setProfile(JSON.parse(savedProfile));
    if (savedAppState) setAppState(JSON.parse(savedAppState) as AppState);
  }, []);

  // Save state to memory
  useEffect(() => {
    // Only save if there is actually content to save
    if (messages.length > 0) {
      localStorage.setItem('pg_messages', JSON.stringify(messages));
      localStorage.setItem('pg_profile', JSON.stringify(profile));
      localStorage.setItem('pg_appstate', JSON.stringify(appState));
    }
  }, [messages, profile, appState]);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isTyping]);

  const startInterview = async () => {
    setAppState('chatting');
    setIsTyping(true);
    const initialGreeting: Message = { 
      role: 'assistant', 
      content: "Hello! I'm PortfolioGenie. I'm here to help you build a stunning resume and a personal website. Let's start with the basics—what is your full name and what role are you targeting (e.g., Software Engineer, Marketing Manager)? You can also upload your current resume as an image or video if you want me to analyze it!" 
    };
    setMessages([initialGreeting]);
    setIsTyping(false);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files) return;

    Array.from(files).forEach((file: File) => {
      const reader = new FileReader();
      reader.onload = (event) => {
        const base64 = (event.target?.result as string).split(',')[1];
        setPendingAttachments(prev => [...prev, {
          mimeType: file.type,
          data: base64,
          name: file.name
        }]);
      };
      reader.readAsDataURL(file);
    });
  };

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if ((!inputText.trim() && pendingAttachments.length === 0) || isTyping) return;

    const userMsg: Message = { 
      role: 'user', 
      content: inputText || (pendingAttachments.length > 0 ? "Analyze this file." : ""),
      attachments: pendingAttachments 
    };

    setMessages(prev => [...prev, userMsg]);
    setInputText('');
    setPendingAttachments([]);
    setIsTyping(true);

    try {
      const result = await chatWithGenie([...messages, userMsg], { 
        thinkingMode, 
        attachments: userMsg.attachments 
      });
      setMessages(prev => [...prev, { 
        role: 'assistant', 
        content: result.text,
        sources: result.sources
      }]);
    } catch (err) {
      console.error(err);
    } finally {
      setIsTyping(false);
    }
  };

  const generatePreview = async () => {
    setIsTyping(true);
    const data = await extractProfileData(messages);
    if (data) {
      setProfile(prev => ({ ...data, themeColor: prev.themeColor }));
      setAppState('preview');
    }
    setIsTyping(false);
  };

  const clearMemory = () => {
    if (confirm("Clear all progress and start over?")) {
      localStorage.removeItem('pg_messages');
      localStorage.removeItem('pg_profile');
      localStorage.removeItem('pg_appstate');
      setMessages([]);
      setProfile(INITIAL_PROFILE);
      setAppState('landing');
      setInputText('');
      setPendingAttachments([]);
      window.location.reload();
    }
  };

  const handleShare = async () => {
    try {
      const jsonStr = JSON.stringify(profile);
      const encodedData = btoa(unescape(encodeURIComponent(jsonStr)));
      const shareUrl = `${window.location.origin}${window.location.pathname}#share=${encodedData}`;

      if (navigator.share) {
        await navigator.share({
          title: `Professional Profile - ${profile.name}`,
          text: `Check out my AI-generated professional profile created with PortfolioGenie!`,
          url: shareUrl,
        });
      } else {
        await navigator.clipboard.writeText(shareUrl);
        setShowShareToast(true);
        setTimeout(() => setShowShareToast(false), 3000);
      }
    } catch (err) {
      console.error("Error sharing profile:", err);
    }
  };

  const exportAsPDF = () => {
    const isResume = previewTab === 'resume';
    const element = document.querySelector(isResume ? '#resume-container' : '#website-preview-container');

    if (!element) {
      alert("Preview element not found. Please try again.");
      return;
    }

    const opt = {
      margin: 0,
      filename: `${profile.name || 'portfolio'}-${previewTab}.pdf`,
      image: { type: 'jpeg', quality: 0.98 },
      html2canvas: { 
        scale: 2, 
        useCORS: true,
        letterRendering: true,
        logging: false
      },
      jsPDF: { unit: 'in', format: 'letter', orientation: 'portrait' }
    };

    // Use html2pdf if available, else fallback to print
    if (typeof html2pdf !== 'undefined') {
      html2pdf().set(opt).from(element).save();
    } else {
      window.print();
    }
  };

  const exportAsHTML = () => {
    const isResume = previewTab === 'resume';
    const fileName = `${profile.name || 'portfolio'}-${previewTab}.html`;

    const element = document.querySelector(isResume ? '#resume-container' : '#website-preview-container');
    const content = element?.outerHTML || 'Content missing';

    const htmlContent = `
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>${profile.name || 'Portfolio'} - ${previewTab.toUpperCase()}</title>
    <script src="https://cdn.tailwindcss.com"></script>
    <link rel="preconnect" href="https://fonts.googleapis.com">
    <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
    <link href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&family=Playfair+Display:wght@700&display=swap" rel="stylesheet">
    <style>
        body { font-family: 'Inter', sans-serif; background-color: #f8fafc; display: flex; justify-content: center; padding: 2rem 1rem; }
        .font-serif { font-family: 'Playfair Display', serif; }
        #resume-container { width: 100%; max-width: 800px; min-height: 1050px; background: white; box-shadow: 0 25px 50px -12px rgb(0 0 0 / 0.25); margin: 0 auto; }
        #website-preview-container { width: 100%; max-width: 1200px; background: white; box-shadow: 0 25px 50px -12px rgb(0 0 0 / 0.25); border-radius: 1rem; overflow: hidden; margin: 0 auto; }
        @media (max-width: 768px) { body { padding: 0; } #resume-container { box-shadow: none; border: none; } #website-preview-container { border-radius: 0; box-shadow: none; } }
    </style>
</head>
<body>
    ${content}
</body>
</html>`;

    const blob = new Blob([htmlContent], { type: 'text/html' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = fileName;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  if (appState === 'landing') {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-900 text-white p-6 overflow-hidden relative">
        <div className="absolute top-0 left-0 w-full h-full bg-[radial-gradient(circle_at_top_right,rgba(79,70,229,0.15),transparent)] pointer-events-none"></div>
        <div className="max-w-4xl text-center z-10">
          <div className="mb-6 inline-block px-4 py-1.5 bg-indigo-500/10 border border-indigo-500/20 rounded-full text-indigo-400 text-sm font-bold tracking-widest uppercase">
            Powered by Gemini 3 Pro
          </div>
          <h1 className="text-6xl md:text-8xl font-serif font-bold mb-8 leading-tight tracking-tighter">
            Elevate your <span className="italic bg-clip-text text-transparent bg-gradient-to-r from-indigo-400 to-cyan-300">professional</span> story.
          </h1>
          <p className="text-xl text-slate-400 mb-12 max-w-2xl mx-auto leading-relaxed">
            PortfolioGenie uses vision, search, and deep reasoning to craft a high-performance resume and website in minutes. 
          </p>
          <button 
            onClick={startInterview}
            className="group px-10 py-5 bg-white text-slate-900 text-xl font-bold rounded-full hover:bg-indigo-50 transition-all flex items-center gap-4 mx-auto shadow-2xl shadow-indigo-500/20"
          >
            Start My Journey
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 group-hover:translate-x-1 transition-transform" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14 5l7 7m0 0l-7 7m7-7H3" />
            </svg>
          </button>
        </div>
      </div>
    );
  }

  if (appState === 'chatting') {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col">
        <header className="bg-white border-b px-8 py-4 flex justify-between items-center sticky top-0 z-20">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white font-black text-xl">P</div>
            <div>
              <h2 className="font-bold text-slate-900 leading-none">PortfolioGenie</h2>
              <span className="text-[10px] text-slate-400 uppercase tracking-widest font-black">Memory Enabled • Deep Thinking</span>
            </div>
          </div>
          <div className="flex items-center gap-4">
            <button 
              onClick={clearMemory}
              className="px-4 py-2 text-slate-400 hover:text-rose-500 transition-colors text-sm font-bold flex items-center gap-2"
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
              </svg>
              Reset
            </button>
            <button 
              onClick={generatePreview}
              className="px-6 py-2.5 bg-indigo-600 text-white rounded-lg font-bold hover:bg-indigo-700 transition-colors shadow-lg shadow-indigo-600/10"
              disabled={messages.length < 2 || isTyping}
            >
              Generate Magic
            </button>
          </div>
        </header>

        <main className="flex-1 flex flex-col max-w-4xl mx-auto w-full p-4 overflow-y-auto pt-12 pb-32">
          {messages.map((m, i) => (
            <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'} mb-8`}>
              <div className={`max-w-[85%] rounded-3xl p-6 ${m.role === 'user' ? 'bg-indigo-600 text-white rounded-tr-none' : 'bg-white text-slate-800 rounded-tl-none shadow-sm border border-slate-100'}`}>
                {m.attachments && m.attachments.length > 0 && (
                  <div className="flex flex-wrap gap-2 mb-4">
                    {m.attachments.map((att, idx) => (
                      <div key={idx} className="bg-slate-900/10 p-2 rounded-lg text-xs flex items-center gap-2">
                        {att.mimeType.startsWith('image/') ? (
                          <img src={`data:${att.mimeType};base64,${att.data}`} className="w-12 h-12 object-cover rounded" alt="upload" />
                        ) : (
                          <div className="w-12 h-12 bg-indigo-500 rounded flex items-center justify-center text-white font-bold">FILE</div>
                        )}
                        <span className="max-w-[100px] truncate">{att.name}</span>
                      </div>
                    ))}
                  </div>
                )}
                <p className="text-lg leading-relaxed whitespace-pre-wrap">{m.content}</p>
                {m.sources && m.sources.length > 0 && (
                  <div className="mt-4 pt-4 border-t border-slate-100 flex flex-wrap gap-2">
                    {m.sources.map((src, sIdx) => (
                      <a 
                        key={sIdx} 
                        href={src.uri} 
                        target="_blank" 
                        rel="noreferrer"
                        className="text-[10px] bg-indigo-50 text-indigo-600 px-2 py-1 rounded hover:bg-indigo-100 transition-colors flex items-center gap-1"
                      >
                        <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
                        </svg>
                        {src.title}
                      </a>
                    ))}
                  </div>
                )}
              </div>
            </div>
          ))}
          {isTyping && (
            <div className="flex justify-start mb-8 animate-pulse">
              <div className="bg-white p-4 rounded-3xl rounded-tl-none shadow-sm border border-slate-100 flex gap-2 items-center">
                <span className="text-xs font-bold text-indigo-400 uppercase tracking-widest">{thinkingMode ? 'Deep Reasoning...' : 'Thinking...'}</span>
                <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce"></div>
                <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce delay-150"></div>
                <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce delay-300"></div>
              </div>
            </div>
          )}
          <div ref={messagesEndRef} />
        </main>

        <footer className="bg-white/80 backdrop-blur-md border-t p-6 sticky bottom-0 z-20">
          <div className="max-w-4xl mx-auto mb-4 flex items-center justify-between">
            <div className="flex gap-4">
              <button 
                type="button"
                onClick={() => fileInputRef.current?.click()}
                className="flex items-center gap-2 text-slate-500 hover:text-indigo-600 transition-colors text-sm font-bold"
              >
                <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.172 7l-6.586 6.586a2 2 0 102.828 2.828l6.414-6.586a4 4 0 00-5.656-5.656l-6.415 6.585a6 6 0 108.486 8.486L20.5 13" />
                </svg>
                Attach Photo/Video
              </button>
              <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" multiple accept="image/*,video/*" />
            </div>

            <div className="flex items-center gap-2">
              <span className={`text-xs font-bold uppercase tracking-widest ${thinkingMode ? 'text-indigo-600' : 'text-slate-400'}`}>Deep Thinking</span>
              <button 
                onClick={() => setThinkingMode(!thinkingMode)}
                className={`w-10 h-5 rounded-full transition-colors relative ${thinkingMode ? 'bg-indigo-600' : 'bg-slate-300'}`}
              >
                <div className={`absolute top-1 w-3 h-3 bg-white rounded-full transition-all ${thinkingMode ? 'left-6' : 'left-1'}`}></div>
              </button>
            </div>
          </div>

          {pendingAttachments.length > 0 && (
            <div className="max-w-4xl mx-auto mb-4 flex flex-wrap gap-2">
              {pendingAttachments.map((att, i) => (
                <div key={i} className="bg-indigo-50 border border-indigo-100 rounded-lg px-3 py-1 text-xs flex items-center gap-2 text-indigo-600">
                  {att.name}
                  <button onClick={() => setPendingAttachments(prev => prev.filter((_, idx) => idx !== i))} className="hover:text-rose-500 font-bold">×</button>
                </div>
              ))}
            </div>
          )}

          <form onSubmit={handleSendMessage} className="max-w-4xl mx-auto flex gap-4">
            <input 
              type="text" 
              value={inputText}
              onChange={(e) => setInputText(e.target.value)}
              placeholder={thinkingMode ? "Ask a complex question..." : "Tell Genie about your experiences..."}
              className="flex-1 bg-slate-100 border-none rounded-2xl px-6 py-4 focus:ring-2 focus:ring-indigo-500 outline-none text-lg"
              disabled={isTyping}
            />
            <button 
              type="submit"
              className="w-14 h-14 bg-indigo-600 text-white rounded-2xl flex items-center justify-center hover:bg-indigo-700 transition-colors disabled:opacity-50"
              disabled={(!inputText.trim() && pendingAttachments.length === 0) || isTyping}
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" />
              </svg>
            </button>
          </form>
        </footer>
      </div>
    );
  }

  if (appState === 'preview') {
    return (
      <div className="min-h-screen bg-slate-100 flex flex-col">
        {/* Toast Notification */}
        {showShareToast && (
          <div className="fixed top-24 left-1/2 -translate-x-1/2 bg-slate-900 text-white px-6 py-3 rounded-full shadow-2xl z-[100] animate-bounce font-bold">
            Link copied to clipboard! 🚀
          </div>
        )}

        <header className="bg-white border-b px-8 py-4 flex justify-between items-center sticky top-0 z-30 no-print overflow-x-auto">
          <div className="flex items-center gap-6 shrink-0">
             <button onClick={() => setAppState('chatting')} className="text-slate-400 hover:text-slate-900 transition-colors" title="Back to Chat">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" />
                </svg>
             </button>
             <div className="h-6 w-px bg-slate-200"></div>
             <div className="flex bg-slate-100 p-1 rounded-xl">
                <button onClick={() => setPreviewTab('resume')} className={`px-4 py-1.5 rounded-lg text-sm font-bold transition-all ${previewTab === 'resume' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500 hover:text-slate-700'}`}>Resume</button>
                <button onClick={() => setPreviewTab('website')} className={`px-4 py-1.5 rounded-lg text-sm font-bold transition-all ${previewTab === 'website' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500 hover:text-slate-700'}`}>Website</button>
             </div>
          </div>
          <div className="flex items-center gap-4 shrink-0">
             {previewTab === 'website' && (
                <div className="flex gap-2 mr-4 hidden md:flex">
                   {THEME_COLORS.map(c => (
                     <button key={c.name} onClick={() => setProfile(p => ({ ...p, themeColor: c.value }))} className={`w-6 h-6 rounded-full border-2 ${profile.themeColor === c.value ? 'border-slate-900' : 'border-transparent'}`} style={{ backgroundColor: c.value }} title={c.name} />
                   ))}
                </div>
             )}

             <button 
               onClick={handleShare}
               className="flex items-center gap-2 px-4 py-2 border-2 border-slate-200 text-slate-700 rounded-lg font-bold hover:bg-slate-50 transition-colors text-sm"
             >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.632 3.316m-6.632-6l6.632-3.316m0 0a3 3 0 105.367-2.684 3 3 0 00-5.367 2.684zm0 9.316a3 3 0 105.368 2.684 3 3 0 00-5.368-2.684z" />
                </svg>
                Share
             </button>

             <div className="flex gap-2 bg-slate-900 rounded-lg p-1">
                <button onClick={exportAsPDF} className="flex items-center gap-2 px-4 py-1.5 text-white rounded-md font-bold hover:bg-slate-800 transition-colors text-sm" title="Download as PDF">
                   <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                     <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 21h10a2 2 0 002-2V9.414a1 1 0 00-.293-.707l-5.414-5.414A1 1 0 0012.586 3H7a2 2 0 00-2 2v14a2 2 0 002 2z" />
                   </svg>
                   PDF
                </button>
                <div className="w-px bg-slate-700 self-stretch my-1"></div>
                <button onClick={exportAsHTML} className="flex items-center gap-2 px-4 py-1.5 text-white rounded-md font-bold hover:bg-slate-800 transition-colors text-sm" title="Download as HTML">
                   <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                     <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 20l4-16m4 4l4 4-4 4M6 16l-4-4 4-4" />
                   </svg>
                   HTML
                </button>
             </div>
          </div>
        </header>
        <main className="flex-1 overflow-y-auto p-8 flex justify-center">
          {previewTab === 'resume' ? (
            <ResumePreview profile={profile} />
          ) : (
            <div id="website-preview-container" className="w-full max-w-[1200px] shadow-2xl rounded-2xl overflow-hidden border border-slate-200 bg-white">
              <WebsitePreview profile={profile} />
            </div>
          )}
        </main>
      </div>
    );
  }

  return null;
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { AppState, Message, UserProfile, Attachment } from './types';
import { INITIAL_PROFILE, THEME_COLORS } from './constants';
import { chatWithGenie, extractProfileData } from './services/geminiService';
import ResumePreview from './components/ResumePreview';
import WebsitePreview from './components/WebsitePreview';

// Declare html2pdf for TypeScript
declare var html2pdf: any;

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>('landing');
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputText, setInputText] = useState('');
  const [profile, setProfile] = useState<UserProfile>(INITIAL_PROFILE);
  const [isTyping, setIsTyping] = useState(false);
  const [previewTab, setPreviewTab] = useState<'resume' | 'website' | 'code'>('resume');
  const [codeSource, setCodeSource] = useState<'resume' | 'website'>('resume');
  const [isGeneratingPDF, setIsGeneratingPDF] = useState(false);
  const [thinkingMode, setThinkingMode] = useState(false);
  const [pendingAttachments, setPendingAttachments] = useState<Attachment[]>([]);
  const [showToast, setShowToast] = useState<{message: string, type: 'success' | 'info'} | null>(null);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const hash = window.location.hash;
    if (hash.startsWith('#share=')) {
      try {
        const encodedData = hash.replace('#share=', '');
        const decodedData = JSON.parse(decodeURIComponent(escape(atob(encodedData))));
        setProfile(decodedData);
        setAppState('preview');
        window.history.replaceState(null, '', window.location.pathname);
        return;
      } catch (e) {
        console.error("Failed to parse shared profile", e);
      }
    }

    const savedMessages = localStorage.getItem('pg_messages');
    const savedProfile = localStorage.getItem('pg_profile');
    const savedAppState = localStorage.getItem('pg_appstate');

    if (savedMessages) setMessages(JSON.parse(savedMessages));
    if (savedProfile) setProfile(JSON.parse(savedProfile));
    if (savedAppState) setAppState(JSON.parse(savedAppState) as AppState);
  }, []);

  useEffect(() => {
    if (messages.length > 0) {
      localStorage.setItem('pg_messages', JSON.stringify(messages));
      localStorage.setItem('pg_profile', JSON.stringify(profile));
      localStorage.setItem('pg_appstate', JSON.stringify(appState));
    }
  }, [messages, profile, appState]);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isTyping]);

  const startInterview = async () => {
    setAppState('chatting');
    setIsTyping(true);
    const initialGreeting: Message = { 
      role: 'assistant', 
      content: "Hello! I'm PortfolioGenie. I'm here to help you build a stunning resume and a personal website. Let's start with the basics—what is your full name and what role are you targeting? You can also upload your current resume for me to analyze!" 
    };
    setMessages([initialGreeting]);
    setIsTyping(false);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files) return;

    Array.from(files).forEach((file: File) => {
      const reader = new FileReader();
      reader.onload = (event) => {
        const base64 = (event.target?.result as string).split(',')[1];
        setPendingAttachments(prev => [...prev, {
          mimeType: file.type,
          data: base64,
          name: file.name
        }]);
      };
      reader.readAsDataURL(file);
    });
  };

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if ((!inputText.trim() && pendingAttachments.length === 0) || isTyping) return;

    const userMsg: Message = { 
      role: 'user', 
      content: inputText || (pendingAttachments.length > 0 ? "Analyze this file." : ""),
      attachments: pendingAttachments 
    };

    setMessages(prev => [...prev, userMsg]);
    setInputText('');
    setPendingAttachments([]);
    setIsTyping(true);

    try {
      const result = await chatWithGenie([...messages, userMsg], { 
        thinkingMode, 
        attachments: userMsg.attachments 
      });
      setMessages(prev => [...prev, { 
        role: 'assistant', 
        content: result.text,
        sources: result.sources
      }]);
    } catch (err) {
      console.error(err);
    } finally {
      setIsTyping(false);
    }
  };

  const generatePreview = async () => {
    setIsTyping(true);
    const data = await extractProfileData(messages);
    if (data) {
      setProfile(prev => ({ ...data, themeColor: prev.themeColor }));
      setAppState('preview');
      setPreviewTab('resume');
    }
    setIsTyping(false);
  };

  const clearMemory = () => {
    if (confirm("Clear all progress and start over?")) {
      localStorage.removeItem('pg_messages');
      localStorage.removeItem('pg_profile');
      localStorage.removeItem('pg_appstate');
      setMessages([]);
      setProfile(INITIAL_PROFILE);
      setAppState('landing');
      window.location.reload();
    }
  };

  const showNotification = (message: string, type: 'success' | 'info' = 'success') => {
    setShowToast({ message, type });
    setTimeout(() => setShowToast(null), 3000);
  };

  const handleShare = async () => {
    try {
      const jsonStr = JSON.stringify(profile);
      const encodedData = btoa(unescape(encodeURIComponent(jsonStr)));
      const shareUrl = `${window.location.origin}${window.location.pathname}#share=${encodedData}`;

      if (navigator.share) {
        await navigator.share({
          title: `Portfolio - ${profile.name}`,
          text: `Check out my AI-generated profile!`,
          url: shareUrl,
        });
      } else {
        await navigator.clipboard.writeText(shareUrl);
        showNotification("Link copied to clipboard! 🚀");
      }
    } catch (err) {
      console.error("Error sharing profile:", err);
    }
  };

  const exportAsPDF = async () => {
    const targetId = previewTab === 'resume' ? '#resume-container' : '#website-preview-container';
    const element = document.querySelector(targetId);

    if (!element) return;

    setIsGeneratingPDF(true);
    showNotification("Generating high-quality PDF...", "info");

    const opt = {
      margin: 0,
      filename: `${profile.name || 'portfolio'}-${previewTab}.pdf`,
      image: { type: 'jpeg', quality: 0.98 },
      html2canvas: { scale: 2, useCORS: true, letterRendering: true },
      jsPDF: { unit: 'in', format: 'letter', orientation: 'portrait' }
    };

    try {
      await html2pdf().set(opt).from(element).save();
      showNotification("PDF saved successfully!");
    } catch (e) {
      console.error(e);
      window.print();
    } finally {
      setIsGeneratingPDF(false);
    }
  };

  const getFullHTML = (type: 'resume' | 'website') => {
    const element = document.querySelector(type === 'resume' ? '#resume-container' : '#website-preview-container');
    const content = element?.outerHTML || 'Content missing';
    return `
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>${profile.name} - Portfolio</title>
    <script src="https://cdn.tailwindcss.com"></script>
    <link href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&family=Playfair+Display:wght@700&display=swap" rel="stylesheet">
    <style>
        body { font-family: 'Inter', sans-serif; background: #f8fafc; display: flex; justify-content: center; padding: 2rem; }
        .font-serif { font-family: 'Playfair Display', serif; }
        #resume-container { width: 100%; max-width: 800px; min-height: 1050px; background: white; box-shadow: 0 25px 50px -12px rgb(0 0 0 / 0.25); margin: 0 auto; padding: 3rem; }
        #website-preview-container { width: 100%; max-width: 1200px; background: white; box-shadow: 0 25px 50px -12px rgb(0 0 0 / 0.25); border-radius: 1rem; overflow: hidden; margin: 0 auto; }
    </style>
</head>
<body>
    ${content}
</body>
</html>`.trim();
  };

  const exportAsHTML = () => {
    const htmlContent = getFullHTML(previewTab === 'code' ? codeSource : (previewTab as 'resume' | 'website'));
    const blob = new Blob([htmlContent], { type: 'text/html' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${profile.name || 'portfolio'}.html`;
    a.click();
    URL.revokeObjectURL(url);
    showNotification("HTML file downloaded!");
  };

  const copyCode = () => {
    const code = getFullHTML(codeSource);
    navigator.clipboard.writeText(code);
    showNotification("Code copied to clipboard!");
  };

  if (appState === 'landing') {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-900 text-white p-6 overflow-hidden relative">
        <div className="absolute top-0 left-0 w-full h-full bg-[radial-gradient(circle_at_top_right,rgba(79,70,229,0.15),transparent)] pointer-events-none"></div>
        <div className="max-w-4xl text-center z-10">
          <div className="mb-6 inline-block px-4 py-1.5 bg-indigo-500/10 border border-indigo-500/20 rounded-full text-indigo-400 text-sm font-bold tracking-widest uppercase">
            Powered by Gemini 3 Pro
          </div>
          <h1 className="text-6xl md:text-8xl font-serif font-bold mb-8 leading-tight tracking-tighter">
            Elevate your <span className="italic bg-clip-text text-transparent bg-gradient-to-r from-indigo-400 to-cyan-300">professional</span> story.
          </h1>
          <p className="text-xl text-slate-400 mb-12 max-w-2xl mx-auto leading-relaxed">
            PortfolioGenie uses vision and deep reasoning to craft a high-performance resume and website in minutes. 
          </p>
          <button 
            onClick={startInterview}
            className="group px-10 py-5 bg-white text-slate-900 text-xl font-bold rounded-full hover:bg-indigo-50 transition-all flex items-center gap-4 mx-auto shadow-2xl"
          >
            Start My Journey
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 group-hover:translate-x-1 transition-transform" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14 5l7 7m0 0l-7 7m7-7H3" />
            </svg>
          </button>
        </div>
      </div>
    );
  }

  if (appState === 'chatting') {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col">
        <header className="bg-white border-b px-8 py-4 flex justify-between items-center sticky top-0 z-20">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white font-black text-xl">P</div>
            <div>
              <h2 className="font-bold text-slate-900 leading-none">PortfolioGenie</h2>
              <span className="text-[10px] text-slate-400 uppercase tracking-widest font-black">Memory Enabled</span>
            </div>
          </div>
          <div className="flex items-center gap-4">
            <button onClick={clearMemory} className="px-4 py-2 text-slate-400 hover:text-rose-500 transition-colors text-sm font-bold">Reset</button>
            <button 
              onClick={generatePreview}
              className="px-6 py-2.5 bg-indigo-600 text-white rounded-lg font-bold hover:bg-indigo-700 transition-colors shadow-lg"
              disabled={messages.length < 2 || isTyping}
            >
              Generate Magic
            </button>
          </div>
        </header>

        <main className="flex-1 flex flex-col max-w-4xl mx-auto w-full p-4 overflow-y-auto pt-12 pb-32">
          {messages.map((m, i) => (
            <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'} mb-8`}>
              <div className={`max-w-[85%] rounded-3xl p-6 ${m.role === 'user' ? 'bg-indigo-600 text-white rounded-tr-none' : 'bg-white text-slate-800 rounded-tl-none shadow-sm border border-slate-100'}`}>
                {m.attachments && m.attachments.length > 0 && (
                  <div className="flex flex-wrap gap-2 mb-4">
                    {m.attachments.map((att, idx) => (
                      <div key={idx} className="bg-slate-900/10 p-2 rounded-lg text-xs flex items-center gap-2">
                        {att.mimeType.startsWith('image/') ? <img src={`data:${att.mimeType};base64,${att.data}`} className="w-12 h-12 object-cover rounded" alt="upload" /> : <div className="w-12 h-12 bg-indigo-500 rounded flex items-center justify-center text-white">FILE</div>}
                        <span className="max-w-[100px] truncate">{att.name}</span>
                      </div>
                    ))}
                  </div>
                )}
                <p className="text-lg leading-relaxed whitespace-pre-wrap">{m.content}</p>
              </div>
            </div>
          ))}
          {isTyping && (
            <div className="flex justify-start mb-8 animate-pulse">
              <div className="bg-white p-4 rounded-3xl rounded-tl-none shadow-sm border border-slate-100 flex gap-2 items-center">
                <span className="text-xs font-bold text-indigo-400 tracking-widest uppercase">{thinkingMode ? 'Deep Reasoning...' : 'Thinking...'}</span>
              </div>
            </div>
          )}
          <div ref={messagesEndRef} />
        </main>

        <footer className="bg-white/80 backdrop-blur-md border-t p-6 sticky bottom-0 z-20">
          <div className="max-w-4xl mx-auto mb-4 flex items-center justify-between">
            <button type="button" onClick={() => fileInputRef.current?.click()} className="flex items-center gap-2 text-slate-500 hover:text-indigo-600 font-bold text-sm">
              <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.172 7l-6.586 6.586a2 2 0 102.828 2.828l6.414-6.586a4 4 0 00-5.656-5.656l-6.415 6.585a6 6 0 108.486 8.486L20.5 13" /></svg>
              Attach
            </button>
            <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" multiple accept="image/*,video/*" />
            <div className="flex items-center gap-2">
              <span className={`text-xs font-bold uppercase ${thinkingMode ? 'text-indigo-600' : 'text-slate-400'}`}>Deep Thinking</span>
              <button onClick={() => setThinkingMode(!thinkingMode)} className={`w-10 h-5 rounded-full relative transition-colors ${thinkingMode ? 'bg-indigo-600' : 'bg-slate-300'}`}>
                <div className={`absolute top-1 w-3 h-3 bg-white rounded-full transition-all ${thinkingMode ? 'left-6' : 'left-1'}`}></div>
              </button>
            </div>
          </div>
          <form onSubmit={handleSendMessage} className="max-w-4xl mx-auto flex gap-4">
            <input type="text" value={inputText} onChange={(e) => setInputText(e.target.value)} placeholder="Tell Genie about your experiences..." className="flex-1 bg-slate-100 rounded-2xl px-6 py-4 focus:ring-2 focus:ring-indigo-500 outline-none text-lg" />
            <button type="submit" className="w-14 h-14 bg-indigo-600 text-white rounded-2xl flex items-center justify-center disabled:opacity-50" disabled={isTyping}><svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" /></svg></button>
          </form>
        </footer>
      </div>
    );
  }

  if (appState === 'preview') {
    return (
      <div className="min-h-screen bg-slate-100 flex flex-col">
        {showToast && (
          <div className="fixed top-24 left-1/2 -translate-x-1/2 bg-slate-900 text-white px-6 py-3 rounded-full shadow-2xl z-[100] animate-bounce font-bold text-sm">
            {showToast.message}
          </div>
        )}

        {isGeneratingPDF && (
          <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[200] flex items-center justify-center">
            <div className="bg-white p-8 rounded-3xl shadow-2xl text-center max-w-sm">
              <div className="w-16 h-16 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin mx-auto mb-6"></div>
              <h3 className="text-xl font-bold text-slate-900 mb-2">Preparing PDF</h3>
              <p className="text-slate-500">We're rendering your document with high precision. Please don't close this window.</p>
            </div>
          </div>
        )}

        <header className="bg-white border-b px-8 py-4 flex justify-between items-center sticky top-0 z-30 no-print overflow-x-auto gap-4">
          <div className="flex items-center gap-6 shrink-0">
             <button onClick={() => setAppState('chatting')} className="text-slate-400 hover:text-slate-900 transition-colors" title="Back to Chat">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" /></svg>
             </button>
             <div className="h-6 w-px bg-slate-200"></div>
             <div className="flex bg-slate-100 p-1 rounded-xl">
                <button onClick={() => setPreviewTab('resume')} className={`px-4 py-1.5 rounded-lg text-sm font-bold transition-all ${previewTab === 'resume' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500 hover:text-slate-700'}`}>Resume</button>
                <button onClick={() => setPreviewTab('website')} className={`px-4 py-1.5 rounded-lg text-sm font-bold transition-all ${previewTab === 'website' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500 hover:text-slate-700'}`}>Website</button>
                <button onClick={() => { setPreviewTab('code'); if (previewTab !== 'code') setCodeSource(previewTab as 'resume'|'website'); }} className={`px-4 py-1.5 rounded-lg text-sm font-bold transition-all ${previewTab === 'code' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500 hover:text-slate-700'}`}>Show Code</button>
             </div>
          </div>

          <div className="flex items-center gap-3 shrink-0">
             {previewTab === 'website' && (
                <div className="hidden lg:flex gap-2 mr-4">
                   {THEME_COLORS.map(c => (
                     <button key={c.name} onClick={() => setProfile(p => ({ ...p, themeColor: c.value }))} className={`w-6 h-6 rounded-full border-2 ${profile.themeColor === c.value ? 'border-slate-900' : 'border-transparent'}`} style={{ backgroundColor: c.value }} />
                   ))}
                </div>
             )}

             {previewTab === 'code' && (
               <div className="flex bg-slate-100 p-1 rounded-lg mr-2">
                 <button onClick={() => setCodeSource('resume')} className={`px-3 py-1 text-xs font-bold rounded ${codeSource === 'resume' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-400'}`}>Resume HTML</button>
                 <button onClick={() => setCodeSource('website')} className={`px-3 py-1 text-xs font-bold rounded ${codeSource === 'website' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-400'}`}>Website HTML</button>
               </div>
             )}

             <button onClick={handleShare} className="flex items-center gap-2 px-4 py-2 border-2 border-slate-200 text-slate-700 rounded-lg font-bold hover:bg-slate-50 transition-colors text-sm">
                <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.632 3.316m-6.632-6l6.632-3.316m0 0a3 3 0 105.367-2.684 3 3 0 00-5.367 2.684zm0 9.316a3 3 0 105.368 2.684 3 3 0 00-5.368-2.684z" /></svg>
                Share
             </button>

             <div className="flex gap-2 bg-slate-900 rounded-lg p-1">
                <button onClick={exportAsPDF} className="flex items-center gap-2 px-4 py-1.5 text-white rounded-md font-bold hover:bg-slate-800 transition-colors text-sm">
                   <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 21h10a2 2 0 002-2V9.414a1 1 0 00-.293-.707l-5.414-5.414A1 1 0 0012.586 3H7a2 2 0 00-2 2v14a2 2 0 002 2z" /></svg>
                   PDF
                </button>
                <div className="w-px bg-slate-700 self-stretch my-1"></div>
                <button onClick={exportAsHTML} className="flex items-center gap-2 px-4 py-1.5 text-white rounded-md font-bold hover:bg-slate-800 transition-colors text-sm">
                   <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 20l4-16m4 4l4 4-4 4M6 16l-4-4 4-4" /></svg>
                   HTML
                </button>
             </div>
          </div>
        </header>

        <main className="flex-1 overflow-y-auto p-8 flex flex-col items-center">
          {/* Hidden containers for PDF/Code capture */}
          <div className="hidden">
            <ResumePreview profile={profile} />
            <div id="website-preview-container">
              <WebsitePreview profile={profile} />
            </div>
          </div>

          {previewTab === 'resume' && <ResumePreview profile={profile} />}

          {previewTab === 'website' && (
            <div id="website-live-view" className="w-full max-w-[1200px] shadow-2xl rounded-2xl overflow-hidden border border-slate-200 bg-white">
              <WebsitePreview profile={profile} />
            </div>
          )}

          {previewTab === 'code' && (
            <div className="w-full max-w-5xl bg-[#1e1e1e] rounded-2xl overflow-hidden shadow-2xl flex flex-col">
              <div className="bg-[#2d2d2d] px-6 py-4 flex justify-between items-center border-b border-white/5">
                <div className="flex gap-2">
                  <div className="w-3 h-3 bg-[#ff5f56] rounded-full"></div>
                  <div className="w-3 h-3 bg-[#ffbd2e] rounded-full"></div>
                  <div className="w-3 h-3 bg-[#27c93f] rounded-full"></div>
                </div>
                <div className="text-white/40 text-xs font-mono tracking-widest uppercase">{codeSource === 'resume' ? 'resume.html' : 'website.html'}</div>
                <button onClick={copyCode} className="text-white/60 hover:text-white flex items-center gap-2 text-xs font-bold transition-colors">
                  <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 16H6a2 2 0 01-2-2V6a2 2 0 012-2h8a2 2 0 012 2v2m-6 12h8a2 2 0 002-2v-8a2 2 0 00-2-2h-8a2 2 0 00-2 2v8a2 2 0 002 2z" /></svg>
                  Copy Code
                </button>
              </div>
              <div className="p-8 overflow-x-auto">
                <pre className="font-mono text-sm text-indigo-300 whitespace-pre-wrap selection:bg-indigo-500/30">
                  <code>{getFullHTML(codeSource)}</code>
                </pre>
              </div>
            </div>
          )}
        </main>
      </div>
    );
  }

  return null;
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { AppState, Message, UserProfile, Attachment } from './types';
import { INITIAL_PROFILE, THEME_COLORS } from './constants';
import { chatWithGenie, extractProfileData } from './services/geminiService';
import ResumePreview from './components/ResumePreview';
import WebsitePreview from './components/WebsitePreview';

// Declare html2pdf for TypeScript
declare var html2pdf: any;

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>('landing');
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputText, setInputText] = useState('');
  const [profile, setProfile] = useState<UserProfile>(INITIAL_PROFILE);
  const [isTyping, setIsTyping] = useState(false);
  const [previewTab, setPreviewTab] = useState<'resume' | 'website' | 'code'>('resume');
  const [codeSource, setCodeSource] = useState<'resume' | 'website'>('resume');
  const [isGeneratingPDF, setIsGeneratingPDF] = useState(false);
  const [isSharing, setIsSharing] = useState(false);
  const [thinkingMode, setThinkingMode] = useState(false);
  const [pendingAttachments, setPendingAttachments] = useState<Attachment[]>([]);
  const [showToast, setShowToast] = useState<{message: string, type: 'success' | 'info'} | null>(null);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const hash = window.location.hash;
    if (hash.startsWith('#share=')) {
      try {
        const encodedData = hash.replace('#share=', '');
        const decodedData = JSON.parse(decodeURIComponent(escape(atob(encodedData))));
        setProfile(decodedData);
        setAppState('preview');
        window.history.replaceState(null, '', window.location.pathname);
        return;
      } catch (e) {
        console.error("Failed to parse shared profile", e);
      }
    }

    const savedMessages = localStorage.getItem('pg_messages');
    const savedProfile = localStorage.getItem('pg_profile');
    const savedAppState = localStorage.getItem('pg_appstate');

    if (savedMessages) setMessages(JSON.parse(savedMessages));
    if (savedProfile) setProfile(JSON.parse(savedProfile));
    if (savedAppState) setAppState(JSON.parse(savedAppState) as AppState);
  }, []);

  useEffect(() => {
    if (messages.length > 0) {
      localStorage.setItem('pg_messages', JSON.stringify(messages));
      localStorage.setItem('pg_profile', JSON.stringify(profile));
      localStorage.setItem('pg_appstate', JSON.stringify(appState));
    }
  }, [messages, profile, appState]);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isTyping]);

  const startInterview = async () => {
    setAppState('chatting');
    setIsTyping(true);
    const initialGreeting: Message = { 
      role: 'assistant', 
      content: "Hello! I'm PortfolioGenie. I'm here to help you build a stunning resume and a personal website. Let's start with the basics—what is your full name and what role are you targeting? You can also upload your current resume for me to analyze!" 
    };
    setMessages([initialGreeting]);
    setIsTyping(false);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files) return;

    Array.from(files).forEach((file: File) => {
      const reader = new FileReader();
      reader.onload = (event) => {
        const base64 = (event.target?.result as string).split(',')[1];
        setPendingAttachments(prev => [...prev, {
          mimeType: file.type,
          data: base64,
          name: file.name
        }]);
      };
      reader.readAsDataURL(file);
    });
  };

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if ((!inputText.trim() && pendingAttachments.length === 0) || isTyping) return;

    const userMsg: Message = { 
      role: 'user', 
      content: inputText || (pendingAttachments.length > 0 ? "Analyze this file." : ""),
      attachments: pendingAttachments 
    };

    setMessages(prev => [...prev, userMsg]);
    setInputText('');
    setPendingAttachments([]);
    setIsTyping(true);

    try {
      const result = await chatWithGenie([...messages, userMsg], { 
        thinkingMode, 
        attachments: userMsg.attachments 
      });
      setMessages(prev => [...prev, { 
        role: 'assistant', 
        content: result.text,
        sources: result.sources
      }]);
    } catch (err) {
      console.error(err);
    } finally {
      setIsTyping(false);
    }
  };

  const generatePreview = async () => {
    setIsTyping(true);
    const data = await extractProfileData(messages);
    if (data) {
      setProfile(prev => ({ ...data, themeColor: prev.themeColor }));
      setAppState('preview');
      setPreviewTab('resume');
    }
    setIsTyping(false);
  };

  const clearMemory = () => {
    if (confirm("Clear all progress and start over?")) {
      localStorage.removeItem('pg_messages');
      localStorage.removeItem('pg_profile');
      localStorage.removeItem('pg_appstate');
      setMessages([]);
      setProfile(INITIAL_PROFILE);
      setAppState('landing');
      window.location.reload();
    }
  };

  const showNotification = (message: string, type: 'success' | 'info' = 'success') => {
    setShowToast({ message, type });
    setTimeout(() => setShowToast(null), 3000);
  };

  const handleShare = async () => {
    if (isSharing) return;
    setIsSharing(true);

    try {
      const jsonStr = JSON.stringify(profile);
      const encodedData = btoa(unescape(encodeURIComponent(jsonStr)));
      const shareUrl = `${window.location.origin}${window.location.pathname}#share=${encodedData}`;

      const shareData = {
        title: `Portfolio - ${profile.name}`,
        text: `Check out my AI-generated professional profile!`,
        url: shareUrl,
      };

      // Check if navigator.share is available and can share the specific data
      if (navigator.share && (!navigator.canShare || navigator.canShare(shareData))) {
        try {
          await navigator.share(shareData);
          showNotification("Shared successfully!");
        } catch (shareErr: any) {
          // If the error is not a user cancellation (AbortError), log and fallback
          if (shareErr.name !== 'AbortError') {
            console.warn("Native share failed, falling back to clipboard:", shareErr);
            await navigator.clipboard.writeText(shareUrl);
            showNotification("Share failed, link copied to clipboard instead! 🚀");
          }
        }
      } else {
        // Fallback for browsers that don't support Web Share API
        await navigator.clipboard.writeText(shareUrl);
        showNotification("Link copied to clipboard! 🚀");
      }
    } catch (err) {
      console.error("Error sharing profile:", err);
      showNotification("Could not share. Please try again.", "info");
    } finally {
      setIsSharing(false);
    }
  };

  const exportAsPDF = async () => {
    const targetId = previewTab === 'resume' ? '#resume-container' : '#website-preview-container';
    const element = document.querySelector(targetId);

    if (!element) return;

    setIsGeneratingPDF(true);
    showNotification("Generating high-quality PDF...", "info");

    const opt = {
      margin: 0,
      filename: `${profile.name || 'portfolio'}-${previewTab}.pdf`,
      image: { type: 'jpeg', quality: 0.98 },
      html2canvas: { scale: 2, useCORS: true, letterRendering: true },
      jsPDF: { unit: 'in', format: 'letter', orientation: 'portrait' }
    };

    try {
      await html2pdf().set(opt).from(element).save();
      showNotification("PDF saved successfully!");
    } catch (e) {
      console.error(e);
      window.print();
    } finally {
      setIsGeneratingPDF(false);
    }
  };

  const getFullHTML = (type: 'resume' | 'website') => {
    const element = document.querySelector(type === 'resume' ? '#resume-container' : '#website-preview-container');
    const content = element?.outerHTML || 'Content missing';
    return `
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>${profile.name} - Portfolio</title>
    <script src="https://cdn.tailwindcss.com"></script>
    <link href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&family=Playfair+Display:wght@700&display=swap" rel="stylesheet">
    <style>
        body { font-family: 'Inter', sans-serif; background: #f8fafc; display: flex; justify-content: center; padding: 2rem; }
        .font-serif { font-family: 'Playfair Display', serif; }
        #resume-container { width: 100%; max-width: 800px; min-height: 1050px; background: white; box-shadow: 0 25px 50px -12px rgb(0 0 0 / 0.25); margin: 0 auto; padding: 3rem; }
        #website-preview-container { width: 100%; max-width: 1200px; background: white; box-shadow: 0 25px 50px -12px rgb(0 0 0 / 0.25); border-radius: 1rem; overflow: hidden; margin: 0 auto; }
    </style>
</head>
<body>
    ${content}
</body>
</html>`.trim();
  };

  const exportAsHTML = () => {
    const htmlContent = getFullHTML(previewTab === 'code' ? codeSource : (previewTab as 'resume' | 'website'));
    const blob = new Blob([htmlContent], { type: 'text/html' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${profile.name || 'portfolio'}.html`;
    a.click();
    URL.revokeObjectURL(url);
    showNotification("HTML file downloaded!");
  };

  const copyCode = () => {
    const code = getFullHTML(codeSource);
    navigator.clipboard.writeText(code);
    showNotification("Code copied to clipboard!");
  };

  if (appState === 'landing') {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-900 text-white p-6 overflow-hidden relative">
        <div className="absolute top-0 left-0 w-full h-full bg-[radial-gradient(circle_at_top_right,rgba(79,70,229,0.15),transparent)] pointer-events-none"></div>
        <div className="max-w-4xl text-center z-10">
          <div className="mb-6 inline-block px-4 py-1.5 bg-indigo-500/10 border border-indigo-500/20 rounded-full text-indigo-400 text-sm font-bold tracking-widest uppercase">
            Powered by Gemini 3 Pro
          </div>
          <h1 className="text-6xl md:text-8xl font-serif font-bold mb-8 leading-tight tracking-tighter">
            Elevate your <span className="italic bg-clip-text text-transparent bg-gradient-to-r from-indigo-400 to-cyan-300">professional</span> story.
          </h1>
          <p className="text-xl text-slate-400 mb-12 max-w-2xl mx-auto leading-relaxed">
            PortfolioGenie uses vision and deep reasoning to craft a high-performance resume and website in minutes. 
          </p>
          <button 
            onClick={startInterview}
            className="group px-10 py-5 bg-white text-slate-900 text-xl font-bold rounded-full hover:bg-indigo-50 transition-all flex items-center gap-4 mx-auto shadow-2xl"
          >
            Start My Journey
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 group-hover:translate-x-1 transition-transform" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14 5l7 7m0 0l-7 7m7-7H3" />
            </svg>
          </button>
        </div>
      </div>
    );
  }

  if (appState === 'chatting') {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col">
        <header className="bg-white border-b px-8 py-4 flex justify-between items-center sticky top-0 z-20">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white font-black text-xl">P</div>
            <div>
              <h2 className="font-bold text-slate-900 leading-none">PortfolioGenie</h2>
              <span className="text-[10px] text-slate-400 uppercase tracking-widest font-black">Memory Enabled</span>
            </div>
          </div>
          <div className="flex items-center gap-4">
            <button onClick={clearMemory} className="px-4 py-2 text-slate-400 hover:text-rose-500 transition-colors text-sm font-bold">Reset</button>
            <button 
              onClick={generatePreview}
              className="px-6 py-2.5 bg-indigo-600 text-white rounded-lg font-bold hover:bg-indigo-700 transition-colors shadow-lg"
              disabled={messages.length < 2 || isTyping}
            >
              Generate Magic
            </button>
          </div>
        </header>

        <main className="flex-1 flex flex-col max-w-4xl mx-auto w-full p-4 overflow-y-auto pt-12 pb-32">
          {messages.map((m, i) => (
            <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'} mb-8`}>
              <div className={`max-w-[85%] rounded-3xl p-6 ${m.role === 'user' ? 'bg-indigo-600 text-white rounded-tr-none' : 'bg-white text-slate-800 rounded-tl-none shadow-sm border border-slate-100'}`}>
                {m.attachments && m.attachments.length > 0 && (
                  <div className="flex flex-wrap gap-2 mb-4">
                    {m.attachments.map((att, idx) => (
                      <div key={idx} className="bg-slate-900/10 p-2 rounded-lg text-xs flex items-center gap-2">
                        {att.mimeType.startsWith('image/') ? <img src={`data:${att.mimeType};base64,${att.data}`} className="w-12 h-12 object-cover rounded" alt="upload" /> : <div className="w-12 h-12 bg-indigo-500 rounded flex items-center justify-center text-white">FILE</div>}
                        <span className="max-w-[100px] truncate">{att.name}</span>
                      </div>
                    ))}
                  </div>
                )}
                <p className="text-lg leading-relaxed whitespace-pre-wrap">{m.content}</p>
              </div>
            </div>
          ))}
          {isTyping && (
            <div className="flex justify-start mb-8 animate-pulse">
              <div className="bg-white p-4 rounded-3xl rounded-tl-none shadow-sm border border-slate-100 flex gap-2 items-center">
                <span className="text-xs font-bold text-indigo-400 tracking-widest uppercase">{thinkingMode ? 'Deep Reasoning...' : 'Thinking...'}</span>
              </div>
            </div>
          )}
          <div ref={messagesEndRef} />
        </main>

        <footer className="bg-white/80 backdrop-blur-md border-t p-6 sticky bottom-0 z-20">
          <div className="max-w-4xl mx-auto mb-4 flex items-center justify-between">
            <button type="button" onClick={() => fileInputRef.current?.click()} className="flex items-center gap-2 text-slate-500 hover:text-indigo-600 font-bold text-sm">
              <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.172 7l-6.586 6.586a2 2 0 102.828 2.828l6.414-6.586a4 4 0 00-5.656-5.656l-6.415 6.585a6 6 0 108.486 8.486L20.5 13" /></svg>
              Attach
            </button>
            <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" multiple accept="image/*,video/*" />
            <div className="flex items-center gap-2">
              <span className={`text-xs font-bold uppercase ${thinkingMode ? 'text-indigo-600' : 'text-slate-400'}`}>Deep Thinking</span>
              <button onClick={() => setThinkingMode(!thinkingMode)} className={`w-10 h-5 rounded-full relative transition-colors ${thinkingMode ? 'bg-indigo-600' : 'bg-slate-300'}`}>
                <div className={`absolute top-1 w-3 h-3 bg-white rounded-full transition-all ${thinkingMode ? 'left-6' : 'left-1'}`}></div>
              </button>
            </div>
          </div>
          <form onSubmit={handleSendMessage} className="max-w-4xl mx-auto flex gap-4">
            <input type="text" value={inputText} onChange={(e) => setInputText(e.target.value)} placeholder="Tell Genie about your experiences..." className="flex-1 bg-slate-100 rounded-2xl px-6 py-4 focus:ring-2 focus:ring-indigo-500 outline-none text-lg" />
            <button type="submit" className="w-14 h-14 bg-indigo-600 text-white rounded-2xl flex items-center justify-center disabled:opacity-50" disabled={isTyping}><svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" /></svg></button>
          </form>
        </footer>
      </div>
    );
  }

  if (appState === 'preview') {
    return (
      <div className="min-h-screen bg-slate-100 flex flex-col">
        {showToast && (
          <div className="fixed top-24 left-1/2 -translate-x-1/2 bg-slate-900 text-white px-6 py-3 rounded-full shadow-2xl z-[100] animate-bounce font-bold text-sm">
            {showToast.message}
          </div>
        )}

        {isGeneratingPDF && (
          <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[200] flex items-center justify-center">
            <div className="bg-white p-8 rounded-3xl shadow-2xl text-center max-w-sm">
              <div className="w-16 h-16 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin mx-auto mb-6"></div>
              <h3 className="text-xl font-bold text-slate-900 mb-2">Preparing PDF</h3>
              <p className="text-slate-500">We're rendering your document with high precision. Please don't close this window.</p>
            </div>
          </div>
        )}

        <header className="bg-white border-b px-8 py-4 flex justify-between items-center sticky top-0 z-30 no-print overflow-x-auto gap-4">
          <div className="flex items-center gap-6 shrink-0">
             <button onClick={() => setAppState('chatting')} className="text-slate-400 hover:text-slate-900 transition-colors" title="Back to Chat">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" /></svg>
             </button>
             <div className="h-6 w-px bg-slate-200"></div>
             <div className="flex bg-slate-100 p-1 rounded-xl">
                <button onClick={() => setPreviewTab('resume')} className={`px-4 py-1.5 rounded-lg text-sm font-bold transition-all ${previewTab === 'resume' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500 hover:text-slate-700'}`}>Resume</button>
                <button onClick={() => setPreviewTab('website')} className={`px-4 py-1.5 rounded-lg text-sm font-bold transition-all ${previewTab === 'website' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500 hover:text-slate-700'}`}>Website</button>
                <button onClick={() => { setPreviewTab('code'); if (previewTab !== 'code') setCodeSource(previewTab as 'resume'|'website'); }} className={`px-4 py-1.5 rounded-lg text-sm font-bold transition-all ${previewTab === 'code' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500 hover:text-slate-700'}`}>Show Code</button>
             </div>
          </div>

          <div className="flex items-center gap-3 shrink-0">
             {previewTab === 'website' && (
                <div className="hidden lg:flex gap-2 mr-4">
                   {THEME_COLORS.map(c => (
                     <button key={c.name} onClick={() => setProfile(p => ({ ...p, themeColor: c.value }))} className={`w-6 h-6 rounded-full border-2 ${profile.themeColor === c.value ? 'border-slate-900' : 'border-transparent'}`} style={{ backgroundColor: c.value }} />
                   ))}
                </div>
             )}

             {previewTab === 'code' && (
               <div className="flex bg-slate-100 p-1 rounded-lg mr-2">
                 <button onClick={() => setCodeSource('resume')} className={`px-3 py-1 text-xs font-bold rounded ${codeSource === 'resume' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-400'}`}>Resume HTML</button>
                 <button onClick={() => setCodeSource('website')} className={`px-3 py-1 text-xs font-bold rounded ${codeSource === 'website' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-400'}`}>Website HTML</button>
               </div>
             )}

             <button 
               onClick={handleShare} 
               disabled={isSharing}
               className={`flex items-center gap-2 px-4 py-2 border-2 border-slate-200 text-slate-700 rounded-lg font-bold transition-colors text-sm ${isSharing ? 'opacity-50 cursor-not-allowed' : 'hover:bg-slate-50'}`}
             >
                <svg className={`w-4 h-4 ${isSharing ? 'animate-spin' : ''}`} fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  {isSharing ? (
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
                  ) : (
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.632 3.316m-6.632-6l6.632-3.316m0 0a3 3 0 105.367-2.684 3 3 0 00-5.367 2.684zm0 9.316a3 3 0 105.368 2.684 3 3 0 00-5.368-2.684z" />
                  )}
                </svg>
                {isSharing ? 'Sharing...' : 'Share'}
             </button>

             <div className="flex gap-2 bg-slate-900 rounded-lg p-1">
                <button onClick={exportAsPDF} className="flex items-center gap-2 px-4 py-1.5 text-white rounded-md font-bold hover:bg-slate-800 transition-colors text-sm">
                   <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 21h10a2 2 0 002-2V9.414a1 1 0 00-.293-.707l-5.414-5.414A1 1 0 0012.586 3H7a2 2 0 00-2 2v14a2 2 0 002 2z" /></svg>
                   PDF
                </button>
                <div className="w-px bg-slate-700 self-stretch my-1"></div>
                <button onClick={exportAsHTML} className="flex items-center gap-2 px-4 py-1.5 text-white rounded-md font-bold hover:bg-slate-800 transition-colors text-sm">
                   <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 20l4-16m4 4l4 4-4 4M6 16l-4-4 4-4" /></svg>
                   HTML
                </button>
             </div>
          </div>
        </header>

        <main className="flex-1 overflow-y-auto p-8 flex flex-col items-center">
          {/* Hidden containers for PDF/Code capture */}
          <div className="hidden">
            <ResumePreview profile={profile} />
            <div id="website-preview-container">
              <WebsitePreview profile={profile} />
            </div>
          </div>

          {previewTab === 'resume' && <ResumePreview profile={profile} />}

          {previewTab === 'website' && (
            <div id="website-live-view" className="w-full max-w-[1200px] shadow-2xl rounded-2xl overflow-hidden border border-slate-200 bg-white">
              <WebsitePreview profile={profile} />
            </div>
          )}

          {previewTab === 'code' && (
            <div className="w-full max-w-5xl bg-[#1e1e1e] rounded-2xl overflow-hidden shadow-2xl flex flex-col">
              <div className="bg-[#2d2d2d] px-6 py-4 flex justify-between items-center border-b border-white/5">
                <div className="flex gap-2">
                  <div className="w-3 h-3 bg-[#ff5f56] rounded-full"></div>
                  <div className="w-3 h-3 bg-[#ffbd2e] rounded-full"></div>
                  <div className="w-3 h-3 bg-[#27c93f] rounded-full"></div>
                </div>
                <div className="text-white/40 text-xs font-mono tracking-widest uppercase">{codeSource === 'resume' ? 'resume.html' : 'website.html'}</div>
                <button onClick={copyCode} className="text-white/60 hover:text-white flex items-center gap-2 text-xs font-bold transition-colors">
                  <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 16H6a2 2 0 01-2-2V6a2 2 0 012-2h8a2 2 0 012 2v2m-6 12h8a2 2 0 002-2v-8a2 2 0 00-2-2h-8a2 2 0 00-2 2v8a2 2 0 002 2z" /></svg>
                  Copy Code
                </button>
              </div>
              <div className="p-8 overflow-x-auto">
                <pre className="font-mono text-sm text-indigo-300 whitespace-pre-wrap selection:bg-indigo-500/30">
                  <code>{getFullHTML(codeSource)}</code>
                </pre>
              </div>
            </div>
          )}
        </main>
      </div>
    );
  }

  return null;
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { AppState, Message, UserProfile, Attachment } from './types';
import { INITIAL_PROFILE, THEME_COLORS } from './constants';
import { chatWithGenie, extractProfileData } from './services/geminiService';
import ResumePreview from './components/ResumePreview';
import WebsitePreview from './components/WebsitePreview';

// Declare html2pdf for TypeScript
declare var html2pdf: any;

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>('landing');
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputText, setInputText] = useState('');
  const [profile, setProfile] = useState<UserProfile>(INITIAL_PROFILE);
  const [isTyping, setIsTyping] = useState(false);
  const [previewTab, setPreviewTab] = useState<'resume' | 'website' | 'code' | 'export'>('resume');
  const [codeSource, setCodeSource] = useState<'resume' | 'website'>('resume');
  const [isGeneratingPDF, setIsGeneratingPDF] = useState(false);
  const [isSharing, setIsSharing] = useState(false);
  const [thinkingMode, setThinkingMode] = useState(false);
  const [pendingAttachments, setPendingAttachments] = useState<Attachment[]>([]);
  const [showToast, setShowToast] = useState<{message: string, type: 'success' | 'info' | 'error'} | null>(null);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const hash = window.location.hash;
    if (hash.startsWith('#share=')) {
      try {
        const encodedData = hash.replace('#share=', '');
        const decodedData = JSON.parse(decodeURIComponent(escape(atob(encodedData))));
        setProfile(decodedData);
        setAppState('preview');
        window.history.replaceState(null, '', window.location.pathname);
        return;
      } catch (e) {
        console.error("Failed to parse shared profile", e);
      }
    }

    const savedMessages = localStorage.getItem('pg_messages');
    const savedProfile = localStorage.getItem('pg_profile');
    const savedAppState = localStorage.getItem('pg_appstate');

    if (savedMessages) setMessages(JSON.parse(savedMessages));
    if (savedProfile) setProfile(JSON.parse(savedProfile));
    if (savedAppState) setAppState(JSON.parse(savedAppState) as AppState);
  }, []);

  useEffect(() => {
    if (messages.length > 0) {
      localStorage.setItem('pg_messages', JSON.stringify(messages));
      localStorage.setItem('pg_profile', JSON.stringify(profile));
      localStorage.setItem('pg_appstate', JSON.stringify(appState));
    }
  }, [messages, profile, appState]);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isTyping]);

  const startInterview = async () => {
    setAppState('chatting');
    setIsTyping(true);
    const initialGreeting: Message = { 
      role: 'assistant', 
      content: "Hello! I'm PortfolioGenie. I'm here to help you build a stunning resume and a personal website. Let's start with the basics—what is your full name and what role are you targeting? You can also upload your current resume for me to analyze!" 
    };
    setMessages([initialGreeting]);
    setIsTyping(false);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files) return;

    Array.from(files).forEach((file: File) => {
      const reader = new FileReader();
      reader.onload = (event) => {
        const base64 = (event.target?.result as string).split(',')[1];
        setPendingAttachments(prev => [...prev, {
          mimeType: file.type,
          data: base64,
          name: file.name
        }]);
      };
      reader.readAsDataURL(file);
    });
  };

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if ((!inputText.trim() && pendingAttachments.length === 0) || isTyping) return;

    const userMsg: Message = { 
      role: 'user', 
      content: inputText || (pendingAttachments.length > 0 ? "Analyze this file." : ""),
      attachments: pendingAttachments 
    };

    setMessages(prev => [...prev, userMsg]);
    setInputText('');
    setPendingAttachments([]);
    setIsTyping(true);

    try {
      const result = await chatWithGenie([...messages, userMsg], { 
        thinkingMode, 
        attachments: userMsg.attachments 
      });
      setMessages(prev => [...prev, { 
        role: 'assistant', 
        content: result.text,
        sources: result.sources
      }]);
    } catch (err) {
      console.error(err);
    } finally {
      setIsTyping(false);
    }
  };

  const generatePreview = async () => {
    setIsTyping(true);
    const data = await extractProfileData(messages);
    if (data) {
      setProfile(prev => ({ ...data, themeColor: prev.themeColor }));
      setAppState('preview');
      setPreviewTab('resume');
    }
    setIsTyping(false);
  };

  const clearMemory = () => {
    if (confirm("Clear all progress and start over?")) {
      localStorage.clear();
      window.location.reload();
    }
  };

  const showNotification = (message: string, type: 'success' | 'info' | 'error' = 'success') => {
    setShowToast({ message, type });
    setTimeout(() => setShowToast(null), 3000);
  };

  const handleShare = async () => {
    if (isSharing) return;
    setIsSharing(true);

    try {
      const jsonStr = JSON.stringify(profile);
      const encodedData = btoa(unescape(encodeURIComponent(jsonStr)));
      const shareUrl = `${window.location.origin}${window.location.pathname}#share=${encodedData}`;

      const shareData = {
        title: `Professional Profile - ${profile.name}`,
        text: `Check out my AI-generated profile created with PortfolioGenie!`,
        url: shareUrl,
      };

      if (navigator.share) {
        try {
          await navigator.share(shareData);
          showNotification("Shared successfully!");
        } catch (shareErr: any) {
          if (shareErr.name === 'AbortError') {
            // User cancelled, do nothing
          } else {
            console.warn("Native share failed, falling back to clipboard:", shareErr);
            await navigator.clipboard.writeText(shareUrl);
            showNotification("Link copied to clipboard! 🚀");
          }
        }
      } else {
        await navigator.clipboard.writeText(shareUrl);
        showNotification("Link copied to clipboard! 🚀");
      }
    } catch (err) {
      console.error("Error sharing profile:", err);
      showNotification("Could not share. Please try again.", "error");
    } finally {
      // Add a small delay before allowing next share to prevent race conditions on OS dialogs
      setTimeout(() => setIsSharing(false), 500);
    }
  };

  const exportAsPDF = async () => {
    // PDF always targets the resume container for best results
    const element = document.querySelector('#resume-capture-target');

    if (!element) return;

    setIsGeneratingPDF(true);
    showNotification("Generating high-quality PDF...", "info");

    const opt = {
      margin: 0,
      filename: `${profile.name || 'portfolio'}-resume.pdf`,
      image: { type: 'jpeg', quality: 0.98 },
      html2canvas: { scale: 2, useCORS: true, letterRendering: true },
      jsPDF: { unit: 'in', format: 'letter', orientation: 'portrait' }
    };

    try {
      await html2pdf().set(opt).from(element).save();
      showNotification("PDF downloaded successfully!");
    } catch (e) {
      console.error(e);
      window.print();
    } finally {
      setIsGeneratingPDF(false);
    }
  };

  const getFullHTML = (type: 'resume' | 'website') => {
    const targetId = type === 'resume' ? '#resume-capture-target' : '#website-capture-target';
    const element = document.querySelector(targetId);
    const content = element?.outerHTML || 'Content missing';
    return `
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>${profile.name || 'Portfolio'} - ${type.toUpperCase()}</title>
    <script src="https://cdn.tailwindcss.com"></script>
    <link href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&family=Playfair+Display:wght@700&display=swap" rel="stylesheet">
    <style>
        body { font-family: 'Inter', sans-serif; background: #f8fafc; display: flex; justify-content: center; padding: 2rem; }
        .font-serif { font-family: 'Playfair Display', serif; }
        #resume-container { width: 100%; max-width: 800px; min-height: 1050px; background: white; box-shadow: 0 25px 50px -12px rgb(0 0 0 / 0.25); margin: 0 auto; padding: 3rem; }
        #website-preview-container { width: 100%; max-width: 1200px; background: white; box-shadow: 0 25px 50px -12px rgb(0 0 0 / 0.25); border-radius: 1rem; overflow: hidden; margin: 0 auto; }
    </style>
</head>
<body>
    ${content}
</body>
</html>`.trim();
  };

  const exportAsHTML = (type: 'resume' | 'website') => {
    const htmlContent = getFullHTML(type);
    const blob = new Blob([htmlContent], { type: 'text/html' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${profile.name || 'portfolio'}-${type}.html`;
    a.click();
    URL.revokeObjectURL(url);
    showNotification(`${type.toUpperCase()} HTML downloaded!`);
  };

  const copyCode = () => {
    const code = getFullHTML(codeSource);
    navigator.clipboard.writeText(code);
    showNotification("Code copied to clipboard!");
  };

  if (appState === 'landing') {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-900 text-white p-6 overflow-hidden relative">
        <div className="absolute top-0 left-0 w-full h-full bg-[radial-gradient(circle_at_top_right,rgba(79,70,229,0.15),transparent)] pointer-events-none"></div>
        <div className="max-w-4xl text-center z-10">
          <div className="mb-6 inline-block px-4 py-1.5 bg-indigo-500/10 border border-indigo-500/20 rounded-full text-indigo-400 text-sm font-bold tracking-widest uppercase">
            Powered by Gemini 3 Pro
          </div>
          <h1 className="text-6xl md:text-8xl font-serif font-bold mb-8 leading-tight tracking-tighter">
            Elevate your <span className="italic bg-clip-text text-transparent bg-gradient-to-r from-indigo-400 to-cyan-300">professional</span> story.
          </h1>
          <p className="text-xl text-slate-400 mb-12 max-w-2xl mx-auto leading-relaxed">
            PortfolioGenie uses high-end vision and reasoning to craft a high-performance resume and website in minutes. 
          </p>
          <button 
            onClick={startInterview}
            className="group px-10 py-5 bg-white text-slate-900 text-xl font-bold rounded-full hover:bg-indigo-50 transition-all flex items-center gap-4 mx-auto shadow-2xl"
          >
            Start My Journey
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 group-hover:translate-x-1 transition-transform" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14 5l7 7m0 0l-7 7m7-7H3" />
            </svg>
          </button>
        </div>
      </div>
    );
  }

  if (appState === 'chatting') {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col">
        <header className="bg-white border-b px-8 py-4 flex justify-between items-center sticky top-0 z-20">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white font-black text-xl shadow-lg">P</div>
            <div>
              <h2 className="font-bold text-slate-900 leading-none">PortfolioGenie</h2>
              <span className="text-[10px] text-slate-400 uppercase tracking-widest font-black">AI Career Architect</span>
            </div>
          </div>
          <div className="flex items-center gap-4">
            <button onClick={clearMemory} className="px-4 py-2 text-slate-400 hover:text-rose-500 transition-colors text-sm font-bold">Reset</button>
            <button 
              onClick={generatePreview}
              className="px-6 py-2.5 bg-indigo-600 text-white rounded-lg font-bold hover:bg-indigo-700 transition-all shadow-lg active:scale-95 disabled:opacity-50"
              disabled={messages.length < 2 || isTyping}
            >
              Generate Magic
            </button>
          </div>
        </header>

        <main className="flex-1 flex flex-col max-w-4xl mx-auto w-full p-4 overflow-y-auto pt-12 pb-32">
          {messages.map((m, i) => (
            <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'} mb-8`}>
              <div className={`max-w-[85%] rounded-3xl p-6 ${m.role === 'user' ? 'bg-indigo-600 text-white rounded-tr-none' : 'bg-white text-slate-800 rounded-tl-none shadow-sm border border-slate-100'}`}>
                {m.attachments && m.attachments.length > 0 && (
                  <div className="flex flex-wrap gap-2 mb-4">
                    {m.attachments.map((att, idx) => (
                      <div key={idx} className="bg-slate-900/10 p-2 rounded-lg text-xs flex items-center gap-2">
                        {att.mimeType.startsWith('image/') ? <img src={`data:${att.mimeType};base64,${att.data}`} className="w-12 h-12 object-cover rounded shadow-sm" alt="upload" /> : <div className="w-12 h-12 bg-indigo-500 rounded flex items-center justify-center text-white font-black">AI</div>}
                        <span className="max-w-[100px] truncate">{att.name}</span>
                      </div>
                    ))}
                  </div>
                )}
                <p className="text-lg leading-relaxed whitespace-pre-wrap">{m.content}</p>
              </div>
            </div>
          ))}
          {isTyping && (
            <div className="flex justify-start mb-8">
              <div className="bg-white p-4 rounded-3xl rounded-tl-none shadow-sm border border-slate-100 flex gap-2 items-center">
                <div className="flex gap-1">
                  <div className="w-1.5 h-1.5 bg-indigo-600 rounded-full animate-bounce"></div>
                  <div className="w-1.5 h-1.5 bg-indigo-600 rounded-full animate-bounce delay-100"></div>
                  <div className="w-1.5 h-1.5 bg-indigo-600 rounded-full animate-bounce delay-200"></div>
                </div>
                <span className="text-xs font-bold text-slate-400 tracking-widest uppercase ml-2">{thinkingMode ? 'Deep Reasoning...' : 'Processing...'}</span>
              </div>
            </div>
          )}
          <div ref={messagesEndRef} />
        </main>

        <footer className="bg-white/80 backdrop-blur-md border-t p-6 sticky bottom-0 z-20">
          <div className="max-w-4xl mx-auto mb-4 flex items-center justify-between">
            <button type="button" onClick={() => fileInputRef.current?.click()} className="flex items-center gap-2 text-slate-500 hover:text-indigo-600 font-bold text-sm transition-colors">
              <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.172 7l-6.586 6.586a2 2 0 102.828 2.828l6.414-6.586a4 4 0 00-5.656-5.656l-6.415 6.585a6 6 0 108.486 8.486L20.5 13" /></svg>
              Attach Document/Photo
            </button>
            <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" multiple accept="image/*,video/*,.pdf" />
            <div className="flex items-center gap-2">
              <span className={`text-xs font-bold uppercase transition-colors ${thinkingMode ? 'text-indigo-600' : 'text-slate-400'}`}>Deep Thinking Mode</span>
              <button onClick={() => setThinkingMode(!thinkingMode)} className={`w-10 h-5 rounded-full relative transition-colors ${thinkingMode ? 'bg-indigo-600' : 'bg-slate-300'}`}>
                <div className={`absolute top-1 w-3 h-3 bg-white rounded-full shadow-sm transition-all ${thinkingMode ? 'left-6' : 'left-1'}`}></div>
              </button>
            </div>
          </div>
          <form onSubmit={handleSendMessage} className="max-w-4xl mx-auto flex gap-4">
            <input 
              type="text" 
              value={inputText} 
              onChange={(e) => setInputText(e.target.value)} 
              placeholder="Type your message..." 
              className="flex-1 bg-slate-100 rounded-2xl px-6 py-4 focus:ring-2 focus:ring-indigo-500 outline-none text-lg transition-all"
              disabled={isTyping}
            />
            <button 
              type="submit" 
              className="w-14 h-14 bg-indigo-600 text-white rounded-2xl flex items-center justify-center hover:bg-indigo-700 shadow-lg active:scale-95 transition-all disabled:opacity-50" 
              disabled={isTyping || (!inputText.trim() && pendingAttachments.length === 0)}
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" /></svg>
            </button>
          </form>
        </footer>
      </div>
    );
  }

  if (appState === 'preview') {
    return (
      <div className="min-h-screen bg-slate-100 flex flex-col">
        {showToast && (
          <div className={`fixed top-24 left-1/2 -translate-x-1/2 px-6 py-3 rounded-full shadow-2xl z-[100] animate-bounce font-bold text-sm ${
            showToast.type === 'error' ? 'bg-rose-600 text-white' : 'bg-slate-900 text-white'
          }`}>
            {showToast.message}
          </div>
        )}

        {isGeneratingPDF && (
          <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[200] flex items-center justify-center">
            <div className="bg-white p-8 rounded-3xl shadow-2xl text-center max-w-sm">
              <div className="w-16 h-16 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin mx-auto mb-6"></div>
              <h3 className="text-xl font-bold text-slate-900 mb-2">Architecting PDF</h3>
              <p className="text-slate-500">Perfecting pixels and typography. Please wait a moment.</p>
            </div>
          </div>
        )}

        <header className="bg-white border-b px-8 py-4 flex justify-between items-center sticky top-0 z-30 no-print overflow-x-auto gap-4 shadow-sm">
          <div className="flex items-center gap-6 shrink-0">
             <button onClick={() => setAppState('chatting')} className="text-slate-400 hover:text-slate-900 transition-colors" title="Back to Chat">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" /></svg>
             </button>
             <div className="h-6 w-px bg-slate-200"></div>
             <div className="flex bg-slate-100 p-1 rounded-xl">
                <button onClick={() => setPreviewTab('resume')} className={`px-4 py-1.5 rounded-lg text-sm font-bold transition-all ${previewTab === 'resume' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500 hover:text-slate-700'}`}>Resume</button>
                <button onClick={() => setPreviewTab('website')} className={`px-4 py-1.5 rounded-lg text-sm font-bold transition-all ${previewTab === 'website' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500 hover:text-slate-700'}`}>Website</button>
                <button onClick={() => { setPreviewTab('code'); setCodeSource('website'); }} className={`px-4 py-1.5 rounded-lg text-sm font-bold transition-all ${previewTab === 'code' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500 hover:text-slate-700'}`}>Code</button>
                <button onClick={() => setPreviewTab('export')} className={`px-4 py-1.5 rounded-lg text-sm font-bold transition-all ${previewTab === 'export' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500 hover:text-slate-700'}`}>Export</button>
             </div>
          </div>

          <div className="flex items-center gap-3 shrink-0">
             {previewTab === 'website' && (
                <div className="hidden lg:flex gap-2 mr-4 bg-slate-50 p-1.5 rounded-full shadow-inner">
                   {THEME_COLORS.map(c => (
                     <button key={c.name} onClick={() => setProfile(p => ({ ...p, themeColor: c.value }))} className={`w-6 h-6 rounded-full border-2 transition-transform hover:scale-110 ${profile.themeColor === c.value ? 'border-slate-900' : 'border-transparent'}`} style={{ backgroundColor: c.value }} title={c.name} />
                   ))}
                </div>
             )}

             <button 
               onClick={handleShare} 
               disabled={isSharing}
               className={`flex items-center gap-2 px-4 py-2 border-2 border-slate-200 text-slate-700 rounded-lg font-bold transition-all text-sm ${isSharing ? 'opacity-50 cursor-not-allowed' : 'hover:bg-slate-50 active:scale-95'}`}
             >
                <svg className={`w-4 h-4 ${isSharing ? 'animate-spin' : ''}`} fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  {isSharing ? (
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
                  ) : (
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.632 3.316m-6.632-6l6.632-3.316m0 0a3 3 0 105.367-2.684 3 3 0 00-5.367 2.684zm0 9.316a3 3 0 105.368 2.684 3 3 0 00-5.368-2.684z" />
                  )}
                </svg>
                {isSharing ? 'Sharing...' : 'Share'}
             </button>
          </div>
        </header>

        <main className="flex-1 overflow-y-auto p-4 md:p-12 flex flex-col items-center relative">
          {/* Capturing Targets (Hidden) */}
          <div className="hidden">
            <div id="resume-capture-target">
              <ResumePreview profile={profile} />
            </div>
            <div id="website-capture-target">
              <WebsitePreview profile={profile} />
            </div>
          </div>

          {previewTab === 'resume' && (
            <div className="animate-in fade-in zoom-in duration-300">
              <ResumePreview profile={profile} />
            </div>
          )}

          {previewTab === 'website' && (
            <div className="w-full max-w-[1200px] shadow-2xl rounded-2xl overflow-hidden border border-slate-200 bg-white animate-in slide-in-from-bottom-8 duration-500">
              <WebsitePreview profile={profile} />
            </div>
          )}

          {previewTab === 'code' && (
            <div className="w-full max-w-5xl bg-[#1e1e1e] rounded-2xl overflow-hidden shadow-2xl flex flex-col animate-in zoom-in-95 duration-300">
              <div className="bg-[#2d2d2d] px-6 py-4 flex justify-between items-center border-b border-white/5">
                <div className="flex gap-4 items-center">
                  <div className="flex gap-1.5 mr-4">
                    <div className="w-3 h-3 bg-[#ff5f56] rounded-full"></div>
                    <div className="w-3 h-3 bg-[#ffbd2e] rounded-full"></div>
                    <div className="w-3 h-3 bg-[#27c93f] rounded-full"></div>
                  </div>
                  <div className="flex bg-white/5 p-1 rounded-lg">
                    <button onClick={() => setCodeSource('website')} className={`px-3 py-1 text-[10px] font-bold uppercase tracking-wider rounded transition-all ${codeSource === 'website' ? 'bg-white/10 text-white' : 'text-white/40 hover:text-white/60'}`}>Website.html</button>
                    <button onClick={() => setCodeSource('resume')} className={`px-3 py-1 text-[10px] font-bold uppercase tracking-wider rounded transition-all ${codeSource === 'resume' ? 'bg-white/10 text-white' : 'text-white/40 hover:text-white/60'}`}>Resume.html</button>
                  </div>
                </div>
                <button onClick={copyCode} className="text-white/60 hover:text-white flex items-center gap-2 text-xs font-bold transition-all active:scale-95 bg-white/5 px-3 py-1.5 rounded-lg border border-white/10">
                  <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 16H6a2 2 0 01-2-2V6a2 2 0 012-2h8a2 2 0 012 2v2m-6 12h8a2 2 0 002-2v-8a2 2 0 00-2-2h-8a2 2 0 00-2 2v8a2 2 0 002 2z" /></svg>
                  Copy
                </button>
              </div>
              <div className="p-8 overflow-x-auto max-h-[70vh]">
                <pre className="font-mono text-xs md:text-sm text-indigo-300 whitespace-pre-wrap selection:bg-indigo-500/40">
                  <code>{getFullHTML(codeSource)}</code>
                </pre>
              </div>
            </div>
          )}

          {previewTab === 'export' && (
            <div className="w-full max-w-4xl bg-white rounded-3xl p-12 shadow-xl border border-slate-100 flex flex-col gap-12 animate-in slide-in-from-right-8 duration-500">
              <div className="text-center">
                <h2 className="text-3xl font-serif font-bold text-slate-900 mb-2">Export Center</h2>
                <p className="text-slate-500">Select your preferred format to download your professional assets.</p>
              </div>

              <div className="grid md:grid-cols-2 gap-8">
                {/* PDF Export Card */}
                <div className="group border-2 border-slate-50 hover:border-indigo-100 bg-slate-50/50 hover:bg-white p-8 rounded-2xl transition-all hover:shadow-2xl hover:shadow-indigo-500/5">
                  <div className="w-12 h-12 bg-rose-50 text-rose-600 rounded-xl flex items-center justify-center mb-6 group-hover:scale-110 transition-transform">
                    <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 21h10a2 2 0 002-2V9.414a1 1 0 00-.293-.707l-5.414-5.414A1 1 0 0012.586 3H7a2 2 0 00-2 2v14a2 2 0 002 2z" /></svg>
                  </div>
                  <h3 className="text-xl font-bold text-slate-900 mb-2">Professional PDF</h3>
                  <p className="text-sm text-slate-500 mb-6 leading-relaxed">High-resolution, print-ready PDF resume. Perfect for job applications and applicant tracking systems (ATS).</p>
                  <button 
                    onClick={exportAsPDF}
                    className="w-full py-3 bg-slate-900 text-white rounded-xl font-bold hover:bg-slate-800 transition-colors flex items-center justify-center gap-2 shadow-lg active:scale-95"
                  >
                    Download PDF
                    <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                  </button>
                </div>

                {/* HTML Export Card */}
                <div className="group border-2 border-slate-50 hover:border-cyan-100 bg-slate-50/50 hover:bg-white p-8 rounded-2xl transition-all hover:shadow-2xl hover:shadow-cyan-500/5">
                  <div className="w-12 h-12 bg-cyan-50 text-cyan-600 rounded-xl flex items-center justify-center mb-6 group-hover:scale-110 transition-transform">
                    <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 20l4-16m4 4l4 4-4 4M6 16l-4-4 4-4" /></svg>
                  </div>
                  <h3 className="text-xl font-bold text-slate-900 mb-2">Standalone Website</h3>
                  <p className="text-sm text-slate-500 mb-6 leading-relaxed">A self-contained HTML file of your portfolio website. Host it on GitHub Pages, Netlify, or your own server.</p>
                  <button 
                    onClick={() => exportAsHTML('website')}
                    className="w-full py-3 bg-cyan-600 text-white rounded-xl font-bold hover:bg-cyan-700 transition-colors flex items-center justify-center gap-2 shadow-lg active:scale-95"
                  >
                    Download HTML
                    <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                  </button>
                </div>
              </div>

              <div className="bg-slate-50 rounded-2xl p-6 flex items-center gap-4 border border-slate-100">
                <div className="w-10 h-10 bg-indigo-100 text-indigo-600 rounded-full flex items-center justify-center shrink-0">
                  <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                </div>
                <p className="text-xs text-slate-600 leading-normal">
                  <strong>Tip:</strong> For the best PDF quality, we recommend using Google Chrome or Edge. Ensure backgrounds and graphics are enabled in your print settings if using the manual print fallback.
                </p>
              </div>
            </div>
          )}
        </main>
      </div>
    );
  }

  return null;
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { AppState, Message, UserProfile, Attachment } from './types';
import { INITIAL_PROFILE, THEME_COLORS } from './constants';
import { chatWithGenie, extractProfileData } from './services/geminiService';
import ResumePreview from './components/ResumePreview';
import WebsitePreview from './components/WebsitePreview';

// Declare html2pdf for TypeScript
declare var html2pdf: any;

interface PDFSettings {
  format: 'letter' | 'a4';
  orientation: 'portrait' | 'landscape';
}

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>('landing');
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputText, setInputText] = useState('');
  const [profile, setProfile] = useState<UserProfile>(INITIAL_PROFILE);
  const [isTyping, setIsTyping] = useState(false);
  const [previewTab, setPreviewTab] = useState<'resume' | 'website' | 'code' | 'export'>('resume');
  const [codeSource, setCodeSource] = useState<'resume' | 'website'>('resume');
  const [isGeneratingPDF, setIsGeneratingPDF] = useState(false);
  const [isSharing, setIsSharing] = useState(false);
  const [thinkingMode, setThinkingMode] = useState(false);
  const [pendingAttachments, setPendingAttachments] = useState<Attachment[]>([]);
  const [showToast, setShowToast] = useState<{message: string, type: 'success' | 'info' | 'error'} | null>(null);

  // PDF Settings
  const [pdfSettings, setPdfSettings] = useState<PDFSettings>({ format: 'letter', orientation: 'portrait' });

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const hash = window.location.hash;
    if (hash.startsWith('#share=')) {
      try {
        const encodedData = hash.replace('#share=', '');
        const decodedData = JSON.parse(decodeURIComponent(escape(atob(encodedData))));
        setProfile(decodedData);
        setAppState('preview');
        window.history.replaceState(null, '', window.location.pathname);
        return;
      } catch (e) {
        console.error("Failed to parse shared profile", e);
      }
    }

    const savedMessages = localStorage.getItem('pg_messages');
    const savedProfile = localStorage.getItem('pg_profile');
    const savedAppState = localStorage.getItem('pg_appstate');

    if (savedMessages) setMessages(JSON.parse(savedMessages));
    if (savedProfile) setProfile(JSON.parse(savedProfile));
    if (savedAppState) setAppState(JSON.parse(savedAppState) as AppState);
  }, []);

  useEffect(() => {
    if (messages.length > 0) {
      localStorage.setItem('pg_messages', JSON.stringify(messages));
      localStorage.setItem('pg_profile', JSON.stringify(profile));
      localStorage.setItem('pg_appstate', JSON.stringify(appState));
    }
  }, [messages, profile, appState]);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isTyping]);

  const startInterview = async () => {
    setAppState('chatting');
    setIsTyping(true);
    const initialGreeting: Message = { 
      role: 'assistant', 
      content: "Hello! I'm PortfolioGenie. I'm here to help you build a stunning resume and a personal website. Let's start with the basics—what is your full name and what role are you targeting? You can also upload your current resume for me to analyze!" 
    };
    setMessages([initialGreeting]);
    setIsTyping(false);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files) return;

    Array.from(files).forEach((file: File) => {
      const reader = new FileReader();
      reader.onload = (event) => {
        const base64 = (event.target?.result as string).split(',')[1];
        setPendingAttachments(prev => [...prev, {
          mimeType: file.type,
          data: base64,
          name: file.name
        }]);
      };
      reader.readAsDataURL(file);
    });
  };

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if ((!inputText.trim() && pendingAttachments.length === 0) || isTyping) return;

    const userMsg: Message = { 
      role: 'user', 
      content: inputText || (pendingAttachments.length > 0 ? "Analyze this file." : ""),
      attachments: pendingAttachments 
    };

    setMessages(prev => [...prev, userMsg]);
    setInputText('');
    setPendingAttachments([]);
    setIsTyping(true);

    try {
      const result = await chatWithGenie([...messages, userMsg], { 
        thinkingMode, 
        attachments: userMsg.attachments 
      });
      setMessages(prev => [...prev, { 
        role: 'assistant', 
        content: result.text,
        sources: result.sources
      }]);
    } catch (err) {
      console.error(err);
    } finally {
      setIsTyping(false);
    }
  };

  const generatePreview = async () => {
    setIsTyping(true);
    const data = await extractProfileData(messages);
    if (data) {
      setProfile(prev => ({ ...data, themeColor: prev.themeColor }));
      setAppState('preview');
      setPreviewTab('resume');
    }
    setIsTyping(false);
  };

  const clearMemory = () => {
    if (confirm("Clear all progress and start over?")) {
      localStorage.clear();
      window.location.reload();
    }
  };

  const showNotification = (message: string, type: 'success' | 'info' | 'error' = 'success') => {
    setShowToast({ message, type });
    setTimeout(() => setShowToast(null), 3000);
  };

  const handleShare = async () => {
    if (isSharing) return;
    setIsSharing(true);

    try {
      const jsonStr = JSON.stringify(profile);
      const encodedData = btoa(unescape(encodeURIComponent(jsonStr)));
      const shareUrl = `${window.location.origin}${window.location.pathname}#share=${encodedData}`;

      const shareData = {
        title: `Professional Profile - ${profile.name}`,
        text: `Check out my AI-generated profile created with PortfolioGenie!`,
        url: shareUrl,
      };

      if (navigator.share) {
        try {
          await navigator.share(shareData);
          showNotification("Shared successfully!");
        } catch (shareErr: any) {
          if (shareErr.name === 'AbortError') {
            // User cancelled, do nothing
          } else {
            console.warn("Native share failed, falling back to clipboard:", shareErr);
            await navigator.clipboard.writeText(shareUrl);
            showNotification("Link copied to clipboard! 🚀");
          }
        }
      } else {
        await navigator.clipboard.writeText(shareUrl);
        showNotification("Link copied to clipboard! 🚀");
      }
    } catch (err) {
      console.error("Error sharing profile:", err);
      showNotification("Could not share. Please try again.", "error");
    } finally {
      setTimeout(() => setIsSharing(false), 500);
    }
  };

  const exportAsPDF = async () => {
    const element = document.querySelector('#resume-capture-target');
    if (!element) return;

    setIsGeneratingPDF(true);
    showNotification("Generating high-fidelity PDF...", "info");

    const opt = {
      margin: 0,
      filename: `${profile.name || 'portfolio'}-resume.pdf`,
      image: { type: 'jpeg', quality: 1.0 },
      html2canvas: { 
        scale: 3, // Higher scale for extreme clarity
        useCORS: true, 
        letterRendering: true,
        logging: false,
        windowWidth: 800 // Force fixed width to prevent responsive layout shifts during capture
      },
      jsPDF: { 
        unit: 'in', 
        format: pdfSettings.format, 
        orientation: pdfSettings.orientation 
      },
      pagebreak: { mode: ['avoid-all', 'css', 'legacy'] }
    };

    try {
      // Delay slightly to ensure any final styles are painted
      await new Promise(r => setTimeout(r, 500));
      await html2pdf().set(opt).from(element).save();
      showNotification("PDF ready for download!");
    } catch (e) {
      console.error("PDF Export Error:", e);
      window.print();
    } finally {
      setIsGeneratingPDF(false);
    }
  };

  const getFullHTML = (type: 'resume' | 'website') => {
    const targetId = type === 'resume' ? '#resume-capture-target' : '#website-capture-target';
    const element = document.querySelector(targetId);
    const content = element?.outerHTML || 'Content missing';
    return `
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>${profile.name || 'Portfolio'} - ${type.toUpperCase()}</title>
    <script src="https://cdn.tailwindcss.com"></script>
    <link href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&family=Playfair+Display:wght@700&display=swap" rel="stylesheet">
    <style>
        body { font-family: 'Inter', sans-serif; background: #f8fafc; display: flex; justify-content: center; padding: 2rem; }
        .font-serif { font-family: 'Playfair Display', serif; }
        #resume-container { width: 100%; max-width: 800px; min-height: 1050px; background: white; box-shadow: 0 25px 50px -12px rgb(0 0 0 / 0.25); margin: 0 auto; padding: 3rem; }
        #website-preview-container { width: 100%; max-width: 1200px; background: white; box-shadow: 0 25px 50px -12px rgb(0 0 0 / 0.25); border-radius: 1rem; overflow: hidden; margin: 0 auto; }
    </style>
</head>
<body>
    ${content}
</body>
</html>`.trim();
  };

  const exportAsHTML = (type: 'resume' | 'website') => {
    const htmlContent = getFullHTML(type);
    const blob = new Blob([htmlContent], { type: 'text/html' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${profile.name || 'portfolio'}-${type}.html`;
    a.click();
    URL.revokeObjectURL(url);
    showNotification(`${type.toUpperCase()} template downloaded!`);
  };

  const copyCode = () => {
    const code = getFullHTML(codeSource);
    navigator.clipboard.writeText(code);
    showNotification("Source code copied!");
  };

  if (appState === 'landing') {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-900 text-white p-6 overflow-hidden relative">
        <div className="absolute top-0 left-0 w-full h-full bg-[radial-gradient(circle_at_top_right,rgba(79,70,229,0.15),transparent)] pointer-events-none"></div>
        <div className="max-w-4xl text-center z-10">
          <div className="mb-6 inline-block px-4 py-1.5 bg-indigo-500/10 border border-indigo-500/20 rounded-full text-indigo-400 text-sm font-bold tracking-widest uppercase">
            Powered by Gemini 3 Pro
          </div>
          <h1 className="text-6xl md:text-8xl font-serif font-bold mb-8 leading-tight tracking-tighter">
            Elevate your <span className="italic bg-clip-text text-transparent bg-gradient-to-r from-indigo-400 to-cyan-300">professional</span> story.
          </h1>
          <p className="text-xl text-slate-400 mb-12 max-w-2xl mx-auto leading-relaxed">
            PortfolioGenie uses high-end vision and reasoning to craft a high-performance resume and website in minutes. 
          </p>
          <button 
            onClick={startInterview}
            className="group px-10 py-5 bg-white text-slate-900 text-xl font-bold rounded-full hover:bg-indigo-50 transition-all flex items-center gap-4 mx-auto shadow-2xl"
          >
            Start My Journey
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 group-hover:translate-x-1 transition-transform" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14 5l7 7m0 0l-7 7m7-7H3" />
            </svg>
          </button>
        </div>
      </div>
    );
  }

  if (appState === 'chatting') {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col">
        <header className="bg-white border-b px-8 py-4 flex justify-between items-center sticky top-0 z-20">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white font-black text-xl shadow-lg">P</div>
            <div>
              <h2 className="font-bold text-slate-900 leading-none">PortfolioGenie</h2>
              <span className="text-[10px] text-slate-400 uppercase tracking-widest font-black">AI Career Architect</span>
            </div>
          </div>
          <div className="flex items-center gap-4">
            <button onClick={clearMemory} className="px-4 py-2 text-slate-400 hover:text-rose-500 transition-colors text-sm font-bold">Reset</button>
            <button 
              onClick={generatePreview}
              className="px-6 py-2.5 bg-indigo-600 text-white rounded-lg font-bold hover:bg-indigo-700 transition-all shadow-lg active:scale-95 disabled:opacity-50"
              disabled={messages.length < 2 || isTyping}
            >
              Generate Magic
            </button>
          </div>
        </header>

        <main className="flex-1 flex flex-col max-w-4xl mx-auto w-full p-4 overflow-y-auto pt-12 pb-32">
          {messages.map((m, i) => (
            <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'} mb-8`}>
              <div className={`max-w-[85%] rounded-3xl p-6 ${m.role === 'user' ? 'bg-indigo-600 text-white rounded-tr-none' : 'bg-white text-slate-800 rounded-tl-none shadow-sm border border-slate-100'}`}>
                {m.attachments && m.attachments.length > 0 && (
                  <div className="flex flex-wrap gap-2 mb-4">
                    {m.attachments.map((att, idx) => (
                      <div key={idx} className="bg-slate-900/10 p-2 rounded-lg text-xs flex items-center gap-2">
                        {att.mimeType.startsWith('image/') ? <img src={`data:${att.mimeType};base64,${att.data}`} className="w-12 h-12 object-cover rounded shadow-sm" alt="upload" /> : <div className="w-12 h-12 bg-indigo-500 rounded flex items-center justify-center text-white font-black">AI</div>}
                        <span className="max-w-[100px] truncate">{att.name}</span>
                      </div>
                    ))}
                  </div>
                )}
                <p className="text-lg leading-relaxed whitespace-pre-wrap">{m.content}</p>
              </div>
            </div>
          ))}
          {isTyping && (
            <div className="flex justify-start mb-8">
              <div className="bg-white p-4 rounded-3xl rounded-tl-none shadow-sm border border-slate-100 flex gap-2 items-center">
                <div className="flex gap-1">
                  <div className="w-1.5 h-1.5 bg-indigo-600 rounded-full animate-bounce"></div>
                  <div className="w-1.5 h-1.5 bg-indigo-600 rounded-full animate-bounce delay-100"></div>
                  <div className="w-1.5 h-1.5 bg-indigo-600 rounded-full animate-bounce delay-200"></div>
                </div>
                <span className="text-xs font-bold text-slate-400 tracking-widest uppercase ml-2">{thinkingMode ? 'Deep Reasoning...' : 'Processing...'}</span>
              </div>
            </div>
          )}
          <div ref={messagesEndRef} />
        </main>

        <footer className="bg-white/80 backdrop-blur-md border-t p-6 sticky bottom-0 z-20">
          <div className="max-w-4xl mx-auto mb-4 flex items-center justify-between">
            <button type="button" onClick={() => fileInputRef.current?.click()} className="flex items-center gap-2 text-slate-500 hover:text-indigo-600 font-bold text-sm transition-colors">
              <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.172 7l-6.586 6.586a2 2 0 102.828 2.828l6.414-6.586a4 4 0 00-5.656-5.656l-6.415 6.585a6 6 0 108.486 8.486L20.5 13" /></svg>
              Attach Document/Photo
            </button>
            <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" multiple accept="image/*,video/*,.pdf" />
            <div className="flex items-center gap-2">
              <span className={`text-xs font-bold uppercase transition-colors ${thinkingMode ? 'text-indigo-600' : 'text-slate-400'}`}>Deep Thinking Mode</span>
              <button onClick={() => setThinkingMode(!thinkingMode)} className={`w-10 h-5 rounded-full relative transition-colors ${thinkingMode ? 'bg-indigo-600' : 'bg-slate-300'}`}>
                <div className={`absolute top-1 w-3 h-3 bg-white rounded-full shadow-sm transition-all ${thinkingMode ? 'left-6' : 'left-1'}`}></div>
              </button>
            </div>
          </div>
          <form onSubmit={handleSendMessage} className="max-w-4xl mx-auto flex gap-4">
            <input 
              type="text" 
              value={inputText} 
              onChange={(e) => setInputText(e.target.value)} 
              placeholder="Type your message..." 
              className="flex-1 bg-slate-100 rounded-2xl px-6 py-4 focus:ring-2 focus:ring-indigo-500 outline-none text-lg transition-all"
              disabled={isTyping}
            />
            <button 
              type="submit" 
              className="w-14 h-14 bg-indigo-600 text-white rounded-2xl flex items-center justify-center hover:bg-indigo-700 shadow-lg active:scale-95 transition-all disabled:opacity-50" 
              disabled={isTyping || (!inputText.trim() && pendingAttachments.length === 0)}
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" /></svg>
            </button>
          </form>
        </footer>
      </div>
    );
  }

  if (appState === 'preview') {
    return (
      <div className="min-h-screen bg-slate-100 flex flex-col">
        {showToast && (
          <div className={`fixed top-24 left-1/2 -translate-x-1/2 px-6 py-3 rounded-full shadow-2xl z-[100] animate-bounce font-bold text-sm ${
