          {previewTab === 'export' && (
            <div className="w-full max-w-4xl bg-white rounded-3xl p-6 md:p-12 shadow-xl border border-slate-100 flex flex-col gap-12 animate-in slide-in-from-right-8 duration-500">
              <div className="text-center">
                <h2 className="text-3xl font-serif font-bold text-slate-900 mb-2">Export Center</h2>
                <p className="text-slate-500">Perfected downloads for every professional context.</p>
              </div>

              <div className="grid md:grid-cols-2 gap-8">
                {/* PDF Export Card */}
                <div className="group border-2 border-slate-50 hover:border-rose-100 bg-slate-50/50 hover:bg-white p-8 rounded-2xl transition-all hover:shadow-2xl hover:shadow-rose-500/5">
                  <div className="w-12 h-12 bg-rose-50 text-rose-600 rounded-xl flex items-center justify-center mb-6 group-hover:scale-110 transition-transform">
                    <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 21h10a2 2 0 002-2V9.414a1 1 0 00-.293-.707l-5.414-5.414A1 1 0 0012.586 3H7a2 2 0 00-2 2v14a2 2 0 002 2z" /></svg>
                  </div>
                  <h3 className="text-xl font-bold text-slate-900 mb-2">High-Fidelity PDF</h3>
                  <p className="text-sm text-slate-500 mb-6 leading-relaxed">Pixel-perfect PDF resume optimized for ATS systems and professional printing.</p>

                  {/* PDF Config UI */}
                  <div className="space-y-4 mb-6">
                    <div className="flex flex-col gap-2">
                      <span className="text-[10px] font-bold uppercase tracking-wider text-slate-400">Page Format</span>
                      <div className="flex bg-white rounded-lg border border-slate-100 p-1">
                        <button 
                          onClick={() => setPdfSettings(s => ({ ...s, format: 'letter' }))}
                          className={`flex-1 py-1.5 text-xs font-bold rounded transition-all ${pdfSettings.format === 'letter' ? 'bg-slate-900 text-white shadow-sm' : 'text-slate-500'}`}
                        >
                          Letter (US)
                        </button>
                        <button 
                          onClick={() => setPdfSettings(s => ({ ...s, format: 'a4' }))}
                          className={`flex-1 py-1.5 text-xs font-bold rounded transition-all ${pdfSettings.format === 'a4' ? 'bg-slate-900 text-white shadow-sm' : 'text-slate-500'}`}
