                    <div className="flex flex-col gap-2">
                      <span className="text-[10px] font-bold uppercase tracking-wider text-slate-400">Orientation</span>
                      <div className="flex bg-white rounded-lg border border-slate-100 p-1">
                        <button 
                          onClick={() => setPdfSettings(s => ({ ...s, orientation: 'portrait' }))}
                          className={`flex-1 py-1.5 text-xs font-bold rounded transition-all ${pdfSettings.orientation === 'portrait' ? 'bg-slate-900 text-white shadow-sm' : 'text-slate-500'}`}
                        >
