                        <button 
                          onClick={() => setPdfSettings(s => ({ ...s, orientation: 'landscape' }))}
                          className={`flex-1 py-1.5 text-xs font-bold rounded transition-all ${pdfSettings.orientation === 'landscape' ? 'bg-slate-900 text-white shadow-sm' : 'text-slate-500'}`}
