                    <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 20l4-16m4 4l4 4-4 4M6 16l-4-4 4-4" /></svg>
                  </div>
                  <h3 className="text-xl font-bold text-slate-900 mb-2">Standalone Website</h3>
                  <p className="text-sm text-slate-500 mb-12 leading-relaxed">A clean, self-contained HTML package. Ready to be hosted on any static provider (Netlify, Vercel, GitHub).</p>

                  <div className="space-y-4">
                    <button 
                      onClick={() => exportAsHTML('website')}
                      className="w-full py-4 bg-cyan-600 text-white rounded-xl font-bold hover:bg-cyan-700 transition-all flex items-center justify-center gap-2 shadow-lg shadow-cyan-600/10 active:scale-95"
                    >
                      Download HTML
                      <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                    </button>
                    <p className="text-[10px] text-center text-slate-400 font-medium">Includes all embedded styles and standard fonts.</p>
