              <div className="bg-indigo-50/50 rounded-2xl p-6 flex items-start gap-4 border border-indigo-100/50">
                <div className="w-10 h-10 bg-indigo-100 text-indigo-600 rounded-full flex items-center justify-center shrink-0">
                  <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                </div>
                <div>
                  <h4 className="text-sm font-bold text-indigo-900 mb-1">Precision Export Tip</h4>
                  <p className="text-xs text-indigo-700/80 leading-relaxed">
                    Our high-end renderer uses a 3x scaling factor for retina-quality PDFs. If layouts appear unexpected in the preview, they will be automatically normalized to a standard 800px width during the final PDF capture process for perfect alignment.
                  </p>
                </div>
              </div>
            </div>
          )}
        </main>
      </div>
    );
  }

  return null;
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { AppState, Message, UserProfile, Attachment } from './types';
import { INITIAL_PROFILE, THEME_COLORS } from './constants';
import { chatWithGenie, extractProfileData } from './services/geminiService';
import ResumePreview from './components/ResumePreview';
import WebsitePreview from './components/WebsitePreview';

// Declare html2pdf for TypeScript
declare var html2pdf: any;

interface PDFSettings {
  format: 'letter' | 'a4';
  orientation: 'portrait' | 'landscape';
}

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>('landing');
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputText, setInputText] = useState('');
  const [profile, setProfile] = useState<UserProfile>(INITIAL_PROFILE);
  const [isTyping, setIsTyping] = useState(false);
  const [previewTab, setPreviewTab] = useState<'resume' | 'website' | 'code' | 'export'>('resume');
  const [codeSource, setCodeSource] = useState<'resume' | 'website'>('resume');
  const [isGeneratingPDF, setIsGeneratingPDF] = useState(false);
  const [isSharing, setIsSharing] = useState(false);
  const [thinkingMode, setThinkingMode] = useState(false);
  const [pendingAttachments, setPendingAttachments] = useState<Attachment[]>([]);
  const [showToast, setShowToast] = useState<{message: string, type: 'success' | 'info' | 'error'} | null>(null);

  // PDF Settings
  const [pdfSettings, setPdfSettings] = useState<PDFSettings>({ format: 'letter', orientation: 'portrait' });

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const hash = window.location.hash;
    if (hash.startsWith('#share=')) {
      try {
        const encodedData = hash.replace('#share=', '');
        const decodedData = JSON.parse(decodeURIComponent(escape(atob(encodedData))));
        setProfile(decodedData);
        setAppState('preview');
        window.history.replaceState(null, '', window.location.pathname);
        return;
      } catch (e) {
        console.error("Failed to parse shared profile", e);
      }
    }

    const savedMessages = localStorage.getItem('pg_messages');
    const savedProfile = localStorage.getItem('pg_profile');
    const savedAppState = localStorage.getItem('pg_appstate');

    if (savedMessages) setMessages(JSON.parse(savedMessages));
    if (savedProfile) setProfile(JSON.parse(savedProfile));
    if (savedAppState) setAppState(JSON.parse(savedAppState) as AppState);
  }, []);

  useEffect(() => {
    if (messages.length > 0) {
      localStorage.setItem('pg_messages', JSON.stringify(messages));
      localStorage.setItem('pg_profile', JSON.stringify(profile));
      localStorage.setItem('pg_appstate', JSON.stringify(appState));
    }
  }, [messages, profile, appState]);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isTyping]);

  const startInterview = async () => {
    setAppState('chatting');
    setIsTyping(true);
    const initialGreeting: Message = { 
      role: 'assistant', 
      content: "Hello! I'm PortfolioGenie. I'm here to help you build a stunning resume and a personal website. Let's start with the basics—what is your full name and what role are you targeting? You can also upload your current resume for me to analyze!" 
    };
    setMessages([initialGreeting]);
    setIsTyping(false);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files) return;

    Array.from(files).forEach((file: File) => {
      const reader = new FileReader();
      reader.onload = (event) => {
        const base64 = (event.target?.result as string).split(',')[1];
        setPendingAttachments(prev => [...prev, {
          mimeType: file.type,
          data: base64,
          name: file.name
        }]);
      };
      reader.readAsDataURL(file);
    });
  };

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if ((!inputText.trim() && pendingAttachments.length === 0) || isTyping) return;

    const userMsg: Message = { 
      role: 'user', 
      content: inputText || (pendingAttachments.length > 0 ? "Analyze this file." : ""),
      attachments: pendingAttachments 
    };

    setMessages(prev => [...prev, userMsg]);
    setInputText('');
    setPendingAttachments([]);
    setIsTyping(true);

    try {
      const result = await chatWithGenie([...messages, userMsg], { 
        thinkingMode, 
        attachments: userMsg.attachments 
      });
      setMessages(prev => [...prev, { 
        role: 'assistant', 
        content: result.text,
        sources: result.sources
      }]);
    } catch (err) {
      console.error(err);
    } finally {
      setIsTyping(false);
    }
  };

  const generatePreview = async () => {
    setIsTyping(true);
    const data = await extractProfileData(messages);
    if (data) {
      setProfile(prev => ({ ...data, themeColor: prev.themeColor }));
      setAppState('preview');
      setPreviewTab('resume');
    }
    setIsTyping(false);
  };

  const clearMemory = () => {
    if (confirm("Clear all progress and start over?")) {
      localStorage.clear();
      window.location.reload();
    }
  };

  const showNotification = (message: string, type: 'success' | 'info' | 'error' = 'success') => {
    setShowToast({ message, type });
    setTimeout(() => setShowToast(null), 3000);
  };

  const handleShare = async () => {
    if (isSharing) return;
    setIsSharing(true);

    try {
      const jsonStr = JSON.stringify(profile);
      const encodedData = btoa(unescape(encodeURIComponent(jsonStr)));
      const shareUrl = `${window.location.origin}${window.location.pathname}#share=${encodedData}`;

      const shareData = {
        title: `Professional Profile - ${profile.name}`,
        text: `Check out my AI-generated profile created with PortfolioGenie!`,
        url: shareUrl,
      };

      if (navigator.share) {
        try {
          await navigator.share(shareData);
          showNotification("Shared successfully!");
        } catch (shareErr: any) {
          if (shareErr.name === 'AbortError') {
            // User cancelled, do nothing
          } else {
            console.warn("Native share failed, falling back to clipboard:", shareErr);
            await navigator.clipboard.writeText(shareUrl);
            showNotification("Link copied to clipboard! 🚀");
          }
        }
      } else {
        await navigator.clipboard.writeText(shareUrl);
        showNotification("Link copied to clipboard! 🚀");
