    const opt = {
      margin: 0,
      filename: `${profile.name || 'portfolio'}-resume.pdf`,
      image: { type: 'jpeg', quality: 1.0 },
      html2canvas: { 
        scale: 3, // High resolution for professional print
        useCORS: true, 
        letterRendering: true,
        logging: false,
        windowWidth: 800 // Ensure layout is captured at standard desktop width
      },
      jsPDF: { 
        unit: 'in', 
        format: pdfSettings.format, 
        orientation: pdfSettings.orientation 
      },
      pagebreak: { mode: ['avoid-all', 'css', 'legacy'] }
    };

    try {
      // Delay slightly to ensure images are fully resolved and DOM is stable
      await new Promise(r => setTimeout(r, 800));
      await html2pdf().set(opt).from(element).save();
      showNotification("PDF ready for download!");
    } catch (e) {
      console.error("PDF Export Error:", e);
      showNotification("PDF Export failed. Try using standard Print.", "error");
