import React, { useState, useEffect, useRef } from 'react';
import { AppState, Message, UserProfile, Attachment } from './types';
import { INITIAL_PROFILE, THEME_COLORS } from './constants';
import { chatWithGenie, extractProfileData } from './services/geminiService';
import ResumePreview from './components/ResumePreview';
import WebsitePreview from './components/WebsitePreview';

// Declare html2pdf for TypeScript
declare var html2pdf: any;

interface PDFSettings {
  format: 'letter' | 'a4';
  orientation: 'portrait' | 'landscape';
}

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>('landing');
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputText, setInputText] = useState('');
  const [profile, setProfile] = useState<UserProfile>(INITIAL_PROFILE);
  const [isTyping, setIsTyping] = useState(false);
  const [previewTab, setPreviewTab] = useState<'resume' | 'website' | 'code' | 'export'>('resume');
  const [codeSource, setCodeSource] = useState<'resume' | 'website'>('resume');
  const [isGeneratingPDF, setIsGeneratingPDF] = useState(false);
  const [isSharing, setIsSharing] = useState(false);
  const [thinkingMode, setThinkingMode] = useState(false);
  const [pendingAttachments, setPendingAttachments] = useState<Attachment[]>([]);
  const [showToast, setShowToast] = useState<{message: string, type: 'success' | 'info' | 'error'} | null>(null);

  // PDF Settings
  const [pdfSettings, setPdfSettings] = useState<PDFSettings>({ format: 'letter', orientation: 'portrait' });

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const hash = window.location.hash;
    if (hash.startsWith('#share=')) {
      try {
        const encodedData = hash.replace('#share=', '');
        const decodedData = JSON.parse(decodeURIComponent(escape(atob(encodedData))));
        setProfile(decodedData);
        setAppState('preview');
        window.history.replaceState(null, '', window.location.pathname);
        return;
      } catch (e) {
        console.error("Failed to parse shared profile", e);
      }
    }

    const savedMessages = localStorage.getItem('pg_messages');
    const savedProfile = localStorage.getItem('pg_profile');
    const savedAppState = localStorage.getItem('pg_appstate');

    if (savedMessages) setMessages(JSON.parse(savedMessages));
    if (savedProfile) setProfile(JSON.parse(savedProfile));
    if (savedAppState) setAppState(JSON.parse(savedAppState) as AppState);
  }, []);

  useEffect(() => {
    if (messages.length > 0) {
      localStorage.setItem('pg_messages', JSON.stringify(messages));
      localStorage.setItem('pg_profile', JSON.stringify(profile));
      localStorage.setItem('pg_appstate', JSON.stringify(appState));
    }
  }, [messages, profile, appState]);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isTyping]);

  const startInterview = async () => {
    setAppState('chatting');
    setIsTyping(true);
    const initialGreeting: Message = { 
      role: 'assistant', 
      content: "Hello! I'm PortfolioGenie. I'm here to help you build a stunning resume and a personal website. Let's start with the basics—what is your full name and what role are you targeting? You can also upload your current resume for me to analyze!" 
    };
    setMessages([initialGreeting]);
    setIsTyping(false);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files) return;

    Array.from(files).forEach((file: File) => {
      const reader = new FileReader();
      reader.onload = (event) => {
        const base64 = (event.target?.result as string).split(',')[1];
        setPendingAttachments(prev => [...prev, {
          mimeType: file.type,
          data: base64,
          name: file.name
        }]);
      };
      reader.readAsDataURL(file);
    });
  };

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if ((!inputText.trim() && pendingAttachments.length === 0) || isTyping) return;

    const userMsg: Message = { 
      role: 'user', 
      content: inputText || (pendingAttachments.length > 0 ? "Analyze this file." : ""),
      attachments: pendingAttachments 
    };

    setMessages(prev => [...prev, userMsg]);
    setInputText('');
    setPendingAttachments([]);
    setIsTyping(true);

    try {
      const result = await chatWithGenie([...messages, userMsg], { 
        thinkingMode, 
        attachments: userMsg.attachments 
      });
      setMessages(prev => [...prev, { 
        role: 'assistant', 
        content: result.text,
        sources: result.sources
      }]);
    } catch (err) {
      console.error(err);
    } finally {
      setIsTyping(false);
    }
  };

  const generatePreview = async () => {
    setIsTyping(true);
    const data = await extractProfileData(messages);
    if (data) {
      setProfile(prev => ({ ...data, themeColor: prev.themeColor }));
      setAppState('preview');
      setPreviewTab('resume');
    }
    setIsTyping(false);
  };

  const clearMemory = () => {
    if (confirm("Clear all progress and start over?")) {
      localStorage.clear();
      window.location.reload();
    }
  };

  const showNotification = (message: string, type: 'success' | 'info' | 'error' = 'success') => {
    setShowToast({ message, type });
    setTimeout(() => setShowToast(null), 3000);
  };

  const handleShare = async () => {
    if (isSharing) return;
    setIsSharing(true);

    try {
      const jsonStr = JSON.stringify(profile);
      const encodedData = btoa(unescape(encodeURIComponent(jsonStr)));
      const shareUrl = `${window.location.origin}${window.location.pathname}#share=${encodedData}`;

      const shareData = {
        title: `Professional Profile - ${profile.name}`,
        text: `Check out my AI-generated profile created with PortfolioGenie!`,
        url: shareUrl,
      };

      if (navigator.share) {
        try {
          await navigator.share(shareData);
          showNotification("Shared successfully!");
        } catch (shareErr: any) {
          if (shareErr.name === 'AbortError') {
            // User cancelled, do nothing
          } else {
            console.warn("Native share failed, falling back to clipboard:", shareErr);
            await navigator.clipboard.writeText(shareUrl);
            showNotification("Link copied to clipboard! 🚀");
          }
        }
      } else {
        await navigator.clipboard.writeText(shareUrl);
        showNotification("Link copied to clipboard! 🚀");
      }
    } catch (err) {
      console.error("Error sharing profile:", err);
      showNotification("Could not share. Please try again.", "error");
    } finally {
      setTimeout(() => setIsSharing(false), 500);
    }
  };

  const exportAsPDF = async () => {
    const element = document.querySelector('#resume-capture-target');
    if (!element) return;

    setIsGeneratingPDF(true);
    showNotification("Generating high-fidelity PDF...", "info");

    const opt = {
      margin: 0,
      filename: `${profile.name || 'portfolio'}-resume.pdf`,
      image: { type: 'jpeg', quality: 1.0 },
      html2canvas: { 
        scale: 3, // High resolution for professional print
        useCORS: true, 
        letterRendering: true,
        logging: false,
        windowWidth: 800 // Ensure layout is captured at standard desktop width
      },
      jsPDF: { 
        unit: 'in', 
        format: pdfSettings.format, 
        orientation: pdfSettings.orientation 
      },
      pagebreak: { mode: ['avoid-all', 'css', 'legacy'] }
    };

    try {
      // Delay slightly to ensure images are fully resolved and DOM is stable
      await new Promise(r => setTimeout(r, 800));
      await html2pdf().set(opt).from(element).save();
      showNotification("PDF ready for download!");
    } catch (e) {
      console.error("PDF Export Error:", e);
      showNotification("PDF Export failed. Try using standard Print.", "error");
      window.print();
    } finally {
      setIsGeneratingPDF(false);
    }
  };

  const getFullHTML = (type: 'resume' | 'website') => {
    const targetId = type === 'resume' ? '#resume-capture-target' : '#website-capture-target';
    const element = document.querySelector(targetId);
    const content = element?.outerHTML || 'Content missing';
    return `
<!DOCTYPE html>
<html lang="en" class="scroll-smooth">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>${profile.name || 'Portfolio'} - ${type.toUpperCase()}</title>
    <script src="https://cdn.tailwindcss.com"></script>
    <link href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&family=Playfair+Display:wght@700&display=swap" rel="stylesheet">
    <style>
        html { scroll-behavior: smooth; }
        body { font-family: 'Inter', sans-serif; background: #f8fafc; display: flex; justify-content: center; padding: 2rem; }
        .font-serif { font-family: 'Playfair Display', serif; }
        #resume-container { width: 100%; max-width: 800px; min-height: 1050px; background: white; box-shadow: 0 25px 50px -12px rgb(0 0 0 / 0.25); margin: 0 auto; padding: 3rem; }
        #website-preview-container { width: 100%; max-width: 1200px; background: white; box-shadow: 0 25px 50px -12px rgb(0 0 0 / 0.25); border-radius: 1rem; overflow: hidden; margin: 0 auto; }
    </style>
</head>
<body>
    ${content}
</body>
</html>`.trim();
  };

  const exportAsHTML = (type: 'resume' | 'website') => {
    const htmlContent = getFullHTML(type);
    const blob = new Blob([htmlContent], { type: 'text/html' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${profile.name || 'portfolio'}-${type}.html`;
    a.click();
    URL.revokeObjectURL(url);
    showNotification(`${type.toUpperCase()} package ready!`);
  };

  const copyCode = () => {
    const code = getFullHTML(codeSource);
    navigator.clipboard.writeText(code);
    showNotification("Code copied to clipboard!");
  };

  if (appState === 'landing') {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-900 text-white p-6 overflow-hidden relative">
        <div className="absolute top-0 left-0 w-full h-full bg-[radial-gradient(circle_at_top_right,rgba(79,70,229,0.15),transparent)] pointer-events-none"></div>
        <div className="max-w-4xl text-center z-10">
          <div className="mb-6 inline-block px-4 py-1.5 bg-indigo-500/10 border border-indigo-500/20 rounded-full text-indigo-400 text-sm font-bold tracking-widest uppercase">
            Powered by Gemini 3 Pro
          </div>
          <h1 className="text-6xl md:text-8xl font-serif font-bold mb-8 leading-tight tracking-tighter">
            Elevate your <span className="italic bg-clip-text text-transparent bg-gradient-to-r from-indigo-400 to-cyan-300">professional</span> story.
          </h1>
          <p className="text-xl text-slate-400 mb-12 max-w-2xl mx-auto leading-relaxed">
            PortfolioGenie uses high-end vision and reasoning to craft a high-performance resume and website in minutes. 
          </p>
          <button 
            onClick={startInterview}
            className="group px-10 py-5 bg-white text-slate-900 text-xl font-bold rounded-full hover:bg-indigo-50 transition-all flex items-center gap-4 mx-auto shadow-2xl"
          >
            Start My Journey
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 group-hover:translate-x-1 transition-transform" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14 5l7 7m0 0l-7 7m7-7H3" />
            </svg>
          </button>
        </div>
      </div>
    );
  }

  if (appState === 'chatting') {
    return (
