import React, { useEffect, useState, useRef } from 'react';
import { UserProfile } from '../types';

interface Props {
  profile: UserProfile;
}

const WebsitePreview: React.FC<Props> = ({ profile }) => {
  const [activeSection, setActiveSection] = useState<string>('');
  const themeStyle = { color: profile.themeColor || '#4f46e5' };
  const bgStyle = { backgroundColor: profile.themeColor || '#4f46e5' };
  const containerRef = useRef<HTMLDivElement>(null);

  // Smooth scroll handler that updates hash
  const scrollToSection = (e: React.MouseEvent | null, id: string) => {
    if (e) e.preventDefault();
    const element = document.getElementById(id);
    if (element) {
      element.scrollIntoView({ behavior: 'smooth', block: 'start' });
      window.history.pushState(null, '', `#${id}`);
      setActiveSection(id);
    }
  };

  // Intersection Observer to track active section on scroll
  useEffect(() => {
    const sections = ['about', 'work', 'contact'];
    const observerOptions = {
      root: null, // Relative to viewport
      rootMargin: '-40% 0px -40% 0px', // Trigger when section is roughly in middle
      threshold: 0
    };

    const observer = new IntersectionObserver((entries) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          const id = entry.target.id;
          setActiveSection(id);
          // Silently update hash without jumping
          window.history.replaceState(null, '', `#${id}`);
        }
      });
    }, observerOptions);

    sections.forEach((id) => {
      const el = document.getElementById(id);
      if (el) observer.observe(el);
    });

    return () => observer.disconnect();
  }, []);

  return (
    <div ref={containerRef} className="bg-white min-h-screen text-slate-900 overflow-hidden relative selection:bg-indigo-100 selection:text-indigo-900">
      {/* Decorative gradient background */}
      <div className="absolute top-0 right-0 w-1/2 h-1/2 bg-gradient-to-br from-indigo-50 to-transparent -z-10 blur-3xl opacity-50"></div>

      {/* Navbar */}
      <nav className="max-w-7xl mx-auto px-8 py-8 flex justify-between items-center sticky top-0 bg-white/80 backdrop-blur-md z-50">
        <span 
          className="text-2xl font-black tracking-tighter cursor-pointer" 
          style={themeStyle}
          onClick={() => window.scrollTo({ top: 0, behavior: 'smooth' })}
        >
          {profile.name?.split(' ')[0] || "PG"}.
        </span>
        <div className="flex gap-8 text-sm font-semibold text-slate-500 uppercase tracking-widest">
          {['about', 'work', 'contact'].map((id) => (
            <a 
              key={id}
              href={`#${id}`} 
              onClick={(e) => scrollToSection(e, id)}
              className={`transition-all duration-300 relative py-1 ${
                activeSection === id ? 'text-slate-900' : 'hover:text-slate-900'
              }`}
            >
              {id}
              {activeSection === id && (
                <span 
                  className="absolute bottom-0 left-0 w-full h-0.5 rounded-full animate-in fade-in slide-in-from-left-2" 
                  style={bgStyle}
                ></span>
              )}
            </a>
          ))}
        </div>
      </nav>

      {/* Hero Section */}
      <section className="max-w-7xl mx-auto px-8 py-24 md:py-32 grid md:grid-cols-2 gap-12 items-center">
        <div className="animate-in fade-in slide-in-from-left-8 duration-700">
          <h2 className="text-sm font-bold uppercase tracking-[0.2em] mb-4" style={themeStyle}>Hello, I'm {profile.name || "Your Name"}</h2>
          <h1 className="text-5xl md:text-7xl font-serif leading-tight text-slate-900 mb-8">
