import React, { useEffect, useState, useRef, useMemo } from 'react';
import { UserProfile } from '../types';

interface Props {
  profile: UserProfile;
}

const WebsitePreview: React.FC<Props> = ({ profile }) => {
  const [activeSection, setActiveSection] = useState<string>('');
  const [selectedTech, setSelectedTech] = useState<string>('All');
  const themeStyle = { color: profile.themeColor || '#4f46e5' };
  const bgStyle = { backgroundColor: profile.themeColor || '#4f46e5' };
  const containerRef = useRef<HTMLDivElement>(null);

  // Extract unique technologies from all projects
  const allTechs = useMemo(() => {
    const techs = new Set<string>();
    profile.projects.forEach(p => {
      p.techStack.forEach(t => techs.add(t));
    });
    return ['All', ...Array.from(techs).sort()];
  }, [profile.projects]);

  // Filter projects based on selected tech
  const filteredProjects = useMemo(() => {
    if (selectedTech === 'All') return profile.projects;
    return profile.projects.filter(p => p.techStack.includes(selectedTech));
  }, [profile.projects, selectedTech]);

  // Smooth scroll handler
  const scrollToSection = (e: React.MouseEvent | null, id: string) => {
    if (e) e.preventDefault();
    const element = document.getElementById(id);
    if (element) {
      element.scrollIntoView({ behavior: 'smooth', block: 'start' });
      // Removed history.pushState to fix SecurityError in sandboxed environments
      setActiveSection(id);
    }
  };

  // Intersection Observer to track active section on scroll
  useEffect(() => {
    const sections = ['about', 'work', 'contact'];
    const observerOptions = {
      root: null,
      rootMargin: '-40% 0px -40% 0px',
      threshold: 0
    };

    const observer = new IntersectionObserver((entries) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          const id = entry.target.id;
          setActiveSection(id);
          // Removed history.replaceState to fix SecurityError in sandboxed environments
        }
      });
    }, observerOptions);

    sections.forEach((id) => {
      const el = document.getElementById(id);
      if (el) observer.observe(el);
    });

    return () => observer.disconnect();
  }, []);

  return (
    <div ref={containerRef} className="bg-white min-h-screen text-slate-900 overflow-hidden relative selection:bg-indigo-100 selection:text-indigo-900">
      {/* Decorative gradient background */}
      <div className="absolute top-0 right-0 w-1/2 h-1/2 bg-gradient-to-br from-indigo-50 to-transparent -z-10 blur-3xl opacity-50"></div>

      {/* Navbar */}
      <nav className="max-w-7xl mx-auto px-8 py-8 flex justify-between items-center sticky top-0 bg-white/80 backdrop-blur-md z-50">
        <span 
          className="text-2xl font-black tracking-tighter cursor-pointer" 
          style={themeStyle}
          onClick={() => window.scrollTo({ top: 0, behavior: 'smooth' })}
        >
          {profile.name?.split(' ')[0] || "PG"}.
        </span>
        <div className="flex gap-8 text-sm font-semibold text-slate-500 uppercase tracking-widest">
          {['about', 'work', 'contact'].map((id) => (
            <button 
              key={id}
              onClick={(e) => scrollToSection(e, id)}
