               onClick={handleShare} 
               disabled={isSharing}
               className={`flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-lg font-bold transition-all text-sm ${isSharing ? 'opacity-50 cursor-not-allowed' : 'hover:bg-indigo-700 active:scale-95 shadow-lg shadow-indigo-200'}`}
             >
                <svg className={`w-4 h-4 ${isSharing ? 'animate-spin' : ''}`} fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  {isSharing ? (
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
                  ) : (
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.632 3.316m-6.632-6l6.632-3.316m0 0a3 3 0 105.367-2.684 3 3 0 00-5.367 2.684zm0 9.316a3 3 0 105.368 2.684 3 3 0 00-5.368-2.684z" />
                  )}
                </svg>
                {isSharing ? 'Copying Link...' : 'Share Profile'}
             </button>
          </div>
        </header>

        <main className="flex-1 overflow-y-auto scroll-smooth p-4 md:p-12 flex flex-col items-center relative">
          <div className="absolute opacity-0 pointer-events-none -z-50 overflow-hidden" style={{ width: '800px', height: '0' }}>
            <div id="resume-capture-target" className="bg-white">
              <ResumePreview profile={profile} />
            </div>
            <div id="website-capture-target" className="bg-white">
              <WebsitePreview profile={profile} />
            </div>
          </div>

          {previewTab === 'resume' && (
            <div className="animate-in fade-in zoom-in duration-500">
              <ResumePreview profile={profile} onAddSkill={handleAddSkill} />
            </div>
          )}

          {previewTab === 'website' && (
            <div className="w-full max-w-[1200px] shadow-2xl rounded-2xl overflow-hidden border border-slate-200 bg-white animate-in slide-in-from-bottom-8 duration-500">
              <WebsitePreview profile={profile} />
            </div>
          )}

          {previewTab === 'code' && (
            <div className="w-full max-w-5xl bg-[#1e1e1e] rounded-2xl overflow-hidden shadow-2xl flex flex-col animate-in zoom-in-95 duration-300">
              <div className="bg-[#2d2d2d] px-6 py-4 flex justify-between items-center border-b border-white/5">
                <div className="flex gap-4 items-center">
                  <div className="flex gap-1.5 mr-4">
                    <div className="w-3 h-3 bg-[#ff5f56] rounded-full"></div>
                    <div className="w-3 h-3 bg-[#ffbd2e] rounded-full"></div>
                    <div className="w-3 h-3 bg-[#27c93f] rounded-full"></div>
                  </div>
                  <div className="flex bg-white/5 p-1 rounded-lg">
                    <button onClick={() => setCodeSource('website')} className={`px-3 py-1 text-[10px] font-bold uppercase tracking-wider rounded transition-all ${codeSource === 'website' ? 'bg-white/10 text-white' : 'text-white/40 hover:text-white/60'}`}>Website.html</button>
                    <button onClick={() => setCodeSource('resume')} className={`px-3 py-1 text-[10px] font-bold uppercase tracking-wider rounded transition-all ${codeSource === 'resume' ? 'bg-white/10 text-white' : 'text-white/40 hover:text-white/60'}`}>Resume.html</button>
                  </div>
                </div>
                <button onClick={copyCode} className="text-white/60 hover:text-white flex items-center gap-2 text-xs font-bold transition-all active:scale-95 bg-white/5 px-3 py-1.5 rounded-lg border border-white/10">
                  <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 16H6a2 2 0 01-2-2V6a2 2 0 012-2h8a2 2 0 012 2v2m-6 12h8a2 2 0 002-2v-8a2 2 0 00-2-2h-8a2 2 0 00-2 2v8a2 2 0 002 2z" /></svg>
                  Copy Code
                </button>
              </div>
              <div className="p-8 overflow-x-auto max-h-[70vh]">
                <pre className="font-mono text-xs md:text-sm text-indigo-300 whitespace-pre-wrap selection:bg-indigo-500/40">
                  <code>{getFullHTML(codeSource)}</code>
                </pre>
              </div>
            </div>
          )}

          {previewTab === 'export' && (
            <div className="w-full max-w-6xl grid lg:grid-cols-3 gap-8 animate-in slide-in-from-right-8 duration-500">
              {/* PDF Export Card */}
              <div className="group bg-white border border-slate-200 p-8 rounded-3xl shadow-sm hover:shadow-xl transition-all flex flex-col">
                <div className="w-12 h-12 bg-rose-50 text-rose-600 rounded-2xl flex items-center justify-center mb-6">
                  <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 21h10a2 2 0 002-2V9.414a1 1 0 00-.293-.707l-5.414-5.414A1 1 0 0012.586 3H7a2 2 0 00-2 2v14a2 2 0 002 2z" /></svg>
                </div>
                <h3 className="text-xl font-bold text-slate-900 mb-2">Professional PDF</h3>
                <p className="text-sm text-slate-500 mb-8 leading-relaxed">Standardized format for direct job applications and ATS compatibility.</p>

                <div className="space-y-4 mb-8 mt-auto">
                  <div className="flex bg-slate-100 p-1 rounded-xl">
                    <button onClick={() => setPdfSettings(s => ({ ...s, format: 'letter' }))} className={`flex-1 py-1.5 text-xs font-bold rounded-lg transition-all ${pdfSettings.format === 'letter' ? 'bg-white shadow-sm text-rose-600' : 'text-slate-500'}`}>Letter</button>
                    <button onClick={() => setPdfSettings(s => ({ ...s, format: 'a4' }))} className={`flex-1 py-1.5 text-xs font-bold rounded-lg transition-all ${pdfSettings.format === 'a4' ? 'bg-white shadow-sm text-rose-600' : 'text-slate-500'}`}>A4</button>
                  </div>
                </div>

                <button onClick={exportAsPDF} className="w-full py-4 bg-slate-900 text-white rounded-xl font-bold hover:bg-slate-800 transition-all flex items-center justify-center gap-2">
                  Generate PDF
                </button>
              </div>

              {/* Social Image Card */}
              <div className="group bg-slate-900 border border-slate-800 p-8 rounded-3xl shadow-2xl relative overflow-hidden flex flex-col">
                <div className="absolute top-0 right-0 w-32 h-32 bg-indigo-500/10 rounded-full -translate-y-1/2 translate-x-1/2 blur-2xl"></div>
                <div className="w-12 h-12 bg-indigo-500/20 text-indigo-400 rounded-2xl flex items-center justify-center mb-6">
                  <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h14a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                </div>
                <h3 className="text-xl font-bold text-white mb-2">Social Preview Asset</h3>
                <p className="text-sm text-slate-400 mb-8 leading-relaxed">A high-impact snapshot of your identity optimized for LinkedIn, Twitter, or Instagram sharing.</p>

                <div className="mt-auto">
                  <button 
                    onClick={exportAsImage}
                    disabled={isCapturingImage}
                    className="w-full py-4 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-500 transition-all flex items-center justify-center gap-2 shadow-lg shadow-indigo-600/20 disabled:opacity-50"
                  >
                    {isCapturingImage ? 'Generating snapshot...' : 'Share as Image'}
                  </button>
                </div>
              </div>

              {/* Web Package Card */}
              <div className="group bg-white border border-slate-200 p-8 rounded-3xl shadow-sm hover:shadow-xl transition-all flex flex-col">
                <div className="w-12 h-12 bg-cyan-50 text-cyan-600 rounded-2xl flex items-center justify-center mb-6">
                  <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 20l4-16m4 4l4 4-4 4M6 16l-4-4 4-4" /></svg>
                </div>
                <h3 className="text-xl font-bold text-slate-900 mb-2">Deployment Bundle</h3>
                <p className="text-sm text-slate-500 mb-12 leading-relaxed">Full HTML/CSS bundle ready for personal hosting or advanced customization.</p>

                <button onClick={() => exportAsHTML('website')} className="w-full py-4 border-2 border-slate-900 text-slate-900 rounded-xl font-bold hover:bg-slate-50 transition-all flex items-center justify-center gap-2 mt-auto">
                  Download HTML Package
                </button>
              </div>
            </div>
          )}
        </main>
      </div>
    );
  }

  return null;
};

export default App;
